  /* ---- from js/join/join-builder.js ---- */
/**
 * join-builder.js — DataGlow Multi-file Join Builder (PR AL)
 *
 * Drag two datasets in, DataGlow suggests the join key automatically.
 * Supports: INNER, LEFT, RIGHT, FULL OUTER joins.
 * Result is added as a new dataset (state.datasets.push) via onJoinComplete.
 *
 * Public API:
 *   JoinBuilder.render(containerEl, datasets, onJoinComplete)
 *   JoinBuilder.suggestKey(colsA, colsB) → { keyA, keyB, confidence }
 */

var JoinBuilder = (function () {
  'use strict';

  // ── Key suggestion ─────────────────────────────────────────────────────────
  // Score column pairs: exact name match > similar name > overlapping values
  function suggestKey(colsA, colsB, rowsA, rowsB) {
    var namesA = colsA.map(function (c) { return c.name; });
    var namesB = colsB.map(function (c) { return c.name; });

    // 1. Exact name match
    for (var i = 0; i < namesA.length; i++) {
      for (var j = 0; j < namesB.length; j++) {
        if (namesA[i].toLowerCase() === namesB[j].toLowerCase()) {
          return { keyA: namesA[i], keyB: namesB[j], confidence: 'high', reason: 'Exact name match' };
        }
      }
    }

    // 2. One name contains the other (e.g. "id" in "user_id")
    var idLike = /\bid\b|_id$|^id_/i;
    var idA = namesA.filter(function (n) { return idLike.test(n); });
    var idB = namesB.filter(function (n) { return idLike.test(n); });
    if (idA.length && idB.length) {
      return { keyA: idA[0], keyB: idB[0], confidence: 'medium', reason: 'ID-like column pairing' };
    }

    // 3. Fuzzy: strip underscores/spaces and compare
    var normalize = function (s) { return s.toLowerCase().replace(/[^a-z0-9]/g, ''); };
    for (var a = 0; a < namesA.length; a++) {
      for (var b = 0; b < namesB.length; b++) {
        if (normalize(namesA[a]) === normalize(namesB[b])) {
          return { keyA: namesA[a], keyB: namesB[b], confidence: 'medium', reason: 'Name similarity match' };
        }
      }
    }

    // 4. Overlap in values  -  sample first 30 rows
    if (rowsA && rowsB) {
      var sampleA = rowsA.slice(0, 30);
      var sampleB = rowsB.slice(0, 30);
      var bestScore = 0, bestA = namesA[0], bestB = namesB[0];
      namesA.forEach(function (na) {
        namesB.forEach(function (nb) {
          var valsA = new Set(sampleA.map(function (r) { return String(r[na] || ''); }));
          var valsB = new Set(sampleB.map(function (r) { return String(r[nb] || ''); }));
          var overlap = 0;
          valsA.forEach(function (v) { if (valsB.has(v)) overlap++; });
          var score = overlap / Math.max(valsA.size, valsB.size, 1);
          if (score > bestScore) { bestScore = score; bestA = na; bestB = nb; }
        });
      });
      if (bestScore > 0.3) {
        return { keyA: bestA, keyB: bestB, confidence: 'low', reason: Math.round(bestScore * 100) + '% value overlap' };
      }
    }

    // 5. Fallback: first column of each
    return { keyA: namesA[0] || '', keyB: namesB[0] || '', confidence: 'none', reason: 'No match found  -  select manually' };
  }

  // ── Join execution ─────────────────────────────────────────────────────────
  function executeJoin(dsA, dsB, keyA, keyB, joinType) {
    var rowsA = dsA.rows;
    var rowsB = dsB.rows;

    // Build lookup from B
    var indexB = {};
    rowsB.forEach(function (row) {
      var k = String(row[keyB] == null ? '' : row[keyB]);
      if (!indexB[k]) indexB[k] = [];
      indexB[k].push(row);
    });

    // Merged column list  -  avoid duplicates (keyB becomes keyA)
    var colsA = dsA.columns.map(function (c) { return c.name; });
    var colsB = dsB.columns
      .filter(function (c) { return c.name !== keyB; })
      .map(function (c) { return c.name; });

    // If a colB name clashes with colA (other than key), suffix with _B
    var finalColsB = colsB.map(function (n) {
      return colsA.indexOf(n) !== -1 ? n + '_' + dsB.name.replace(/\.[^.]+$/, '').slice(0, 6) : n;
    });

    var resultRows = [];
    var matchedBKeys = new Set();

    // Left side iteration
    rowsA.forEach(function (rowA) {
      var k = String(rowA[keyA] == null ? '' : rowA[keyA]);
      var bMatches = indexB[k] || [];

      if (bMatches.length) {
        matchedBKeys.add(k);
        bMatches.forEach(function (rowB, bi) {
          var merged = {};
          colsA.forEach(function (c) { merged[c] = rowA[c]; });
          colsB.forEach(function (c, i) { merged[finalColsB[i]] = rowB[c]; });
          resultRows.push(merged);
        });
      } else if (joinType === 'left' || joinType === 'full') {
        // Unmatched left row
        var merged = {};
        colsA.forEach(function (c) { merged[c] = rowA[c]; });
        finalColsB.forEach(function (c) { merged[c] = null; });
        resultRows.push(merged);
      }
    });

    // Right side unmatched (for RIGHT and FULL)
    if (joinType === 'right' || joinType === 'full') {
      rowsB.forEach(function (rowB) {
        var k = String(rowB[keyB] == null ? '' : rowB[keyB]);
        if (!matchedBKeys.has(k)) {
          var merged = {};
          colsA.forEach(function (c) { merged[c] = null; });
          colsB.forEach(function (c, i) { merged[finalColsB[i]] = rowB[c]; });
          merged[keyA] = rowB[keyB]; // copy key from B side
          resultRows.push(merged);
        }
      });
    }

    // Build columns array for result dataset
    var allCols = colsA.concat(finalColsB).map(function (name) {
      // Find type from either dataset
      var srcA = dsA.columns.find(function (c) { return c.name === name; });
      var srcBIdx = finalColsB.indexOf(name);
      var srcB = srcBIdx !== -1 ? dsB.columns.find(function (c) { return c.name === colsB[srcBIdx]; }) : null;
      return { name: name, type: (srcA && srcA.type) || (srcB && srcB.type) || 'text' };
    });

    return {
      columns: allCols,
      rows: resultRows,
      name: dsA.name.replace(/\.[^.]+$/, '') + '_joined',
      filename: dsA.name.replace(/\.[^.]+$/, '') + '_joined.csv',
      findings: [],
      rowFlags: resultRows.map(function () { return { warning: false, error: false }; }),
      columnHealth: null
    };
  }

  // ── UI render ──────────────────────────────────────────────────────────────
  function render(containerEl, getDatasets, onJoinComplete) {
    function rebuild() {
      containerEl.innerHTML = '';
      var datasets = getDatasets();

      if (!datasets || datasets.length < 1) {
        containerEl.innerHTML = [
          '<div class="join-empty">',
          '  <div class="join-empty-icon">&#8644;</div>',
          '  <div class="join-empty-title">Drop two files to join them</div>',
          '  <div class="join-empty-sub">Load your first file, then drop a second  -  DataGlow will suggest the join key automatically.</div>',
          '</div>'
        ].join('');
        return;
      }

      if (datasets.length === 1) {
        containerEl.innerHTML = [
          '<div class="join-empty">',
          '  <div class="join-empty-icon">&#43;</div>',
          '  <div class="join-empty-title">Drop a second file to join</div>',
          '  <div class="join-empty-sub">You have <strong>' + escHtml(datasets[0].name) + '</strong> loaded. Drop another file anywhere to enable joining.</div>',
          '</div>'
        ].join('');
        return;
      }

      // Two or more datasets  -  render the builder
      var dsNames = datasets.map(function (d, i) {
        return '<option value="' + i + '">' + escHtml(d.name) + '</option>';
      });

      // Default: last two
      var defaultA = datasets.length - 2;
      var defaultB = datasets.length - 1;
      var dsA = datasets[defaultA];
      var dsB = datasets[defaultB];
      var suggestion = suggestKey(dsA.columns, dsB.columns, dsA.rows, dsB.rows);

      containerEl.innerHTML = [
        '<div class="join-builder">',
        '  <div class="join-header">',
        '    <span class="join-header-title">Join Builder</span>',
        '    <span class="join-header-sub">Combine two datasets on a shared column</span>',
        '  </div>',

        '  <div class="join-row">',
        '    <div class="join-card" id="jcard-a">',
        '      <div class="join-card-label">Left dataset</div>',
        '      <select class="join-select" id="join-ds-a">' + dsNames.map(function (o, i) { return i === defaultA ? o.replace('<option', '<option selected') : o; }).join('') + '</select>',
        '      <div class="join-col-select-wrap">',
        '        <label class="join-col-label">Join on</label>',
        '        <select class="join-select" id="join-key-a"></select>',
        '      </div>',
        '    </div>',

        '    <div class="join-type-block">',
        '      <div class="join-type-label">Join type</div>',
        '      <div class="join-type-btns">',
        '        <button class="join-type-btn active" data-type="inner" title="Only rows that match in both">INNER</button>',
        '        <button class="join-type-btn" data-type="left"  title="All left rows, matched right">LEFT</button>',
        '        <button class="join-type-btn" data-type="right" title="All right rows, matched left">RIGHT</button>',
        '        <button class="join-type-btn" data-type="full"  title="All rows from both">FULL</button>',
        '      </div>',
        '      <div class="join-venn" id="join-venn"></div>',
        '    </div>',

        '    <div class="join-card" id="jcard-b">',
        '      <div class="join-card-label">Right dataset</div>',
        '      <select class="join-select" id="join-ds-b">' + dsNames.map(function (o, i) { return i === defaultB ? o.replace('<option', '<option selected') : o; }).join('') + '</select>',
        '      <div class="join-col-select-wrap">',
        '        <label class="join-col-label">Join on</label>',
        '        <select class="join-select" id="join-key-b"></select>',
        '      </div>',
        '    </div>',
        '  </div>',

        '  <div class="join-suggestion" id="join-suggestion"></div>',

        '  <div class="join-preview-wrap">',
        '    <div class="join-preview-label">Preview <span id="join-preview-count"></span></div>',
        '    <div id="join-preview-table-wrap"><table id="join-preview-table" class="join-preview-table"></table></div>',
        '  </div>',

        '  <div class="join-actions">',
        '    <button id="join-run-btn" class="join-run-btn">Run Join</button>',
        '  </div>',
        '</div>'
      ].join('');

      // ── Populate key dropdowns ─────────────────────────────────────────────
      function populateKeys(dsAIdx, dsBIdx) {
        var dA = datasets[dsAIdx], dB = datasets[dsBIdx];
        var keyA = containerEl.querySelector('#join-key-a');
        var keyB = containerEl.querySelector('#join-key-b');
        keyA.innerHTML = dA.columns.map(function (c) {
          return '<option value="' + escHtml(c.name) + '">' + escHtml(c.name) + '</option>';
        }).join('');
        keyB.innerHTML = dB.columns.map(function (c) {
          return '<option value="' + escHtml(c.name) + '">' + escHtml(c.name) + '</option>';
        }).join('');

        // Apply suggestion
        var sug = suggestKey(dA.columns, dB.columns, dA.rows, dB.rows);
        if (sug.keyA) keyA.value = sug.keyA;
        if (sug.keyB) keyB.value = sug.keyB;

        var sugEl = containerEl.querySelector('#join-suggestion');
        var conf = sug.confidence;
        var icon = conf === 'high' ? '&#10003;' : conf === 'medium' ? '&#9888;' : conf === 'low' ? '&#x1F4A1;' : '&#x2753;';
        sugEl.className = 'join-suggestion join-sug-' + conf;
        sugEl.innerHTML = '<span class="join-sug-icon">' + icon + '</span>' +
          '<span class="join-sug-text">Suggested key: <strong>' + escHtml(sug.keyA) + '</strong> = <strong>' + escHtml(sug.keyB) + '</strong> &mdash; ' + escHtml(sug.reason) + '</span>';

        updatePreview(dsAIdx, dsBIdx);
      }

      // ── Live preview ───────────────────────────────────────────────────────
      var currentJoinType = 'inner';

      function updatePreview(dsAIdx, dsBIdx) {
        var dA = datasets[dsAIdx], dB = datasets[dsBIdx];
        var keyA = containerEl.querySelector('#join-key-a');
        var keyB = containerEl.querySelector('#join-key-b');
        if (!keyA || !keyB) return;
        var kA = keyA.value, kB = keyB.value;
        if (!kA || !kB) return;

        var result = executeJoin(dA, dB, kA, kB, currentJoinType);
        var preview = result.rows.slice(0, 6);
        var cols = result.columns.slice(0, 8); // cap columns shown in preview

        var countEl = containerEl.querySelector('#join-preview-count');
        if (countEl) countEl.textContent = '(' + result.rows.length.toLocaleString() + ' rows)';

        var table = containerEl.querySelector('#join-preview-table');
        if (!table) return;

        var thead = '<thead><tr>' + cols.map(function (c) {
          return '<th>' + escHtml(c.name) + '</th>';
        }).join('') + (result.columns.length > 8 ? '<th class="join-more-cols">+' + (result.columns.length - 8) + ' more</th>' : '') + '</tr></thead>';

        var tbody = '<tbody>' + preview.map(function (row) {
          return '<tr>' + cols.map(function (c) {
            var v = row[c.name];
            return '<td>' + (v == null ? '<span class="join-null">null</span>' : escHtml(String(v))) + '</td>';
          }).join('') + (result.columns.length > 8 ? '<td></td>' : '') + '</tr>';
        }).join('') + '</tbody>';

        table.innerHTML = thead + tbody;

        // Store result for Run Join
        table._result = result;

        // ── Cardinality check  -  warn before fan-out join runs ───────────
        var cardWrap = containerEl.querySelector('#cardinality-warning-wrap');
        if (!cardWrap) {
          cardWrap = document.createElement('div');
          cardWrap.id = 'cardinality-warning-wrap';
          // Insert above the preview table
          var previewWrap = containerEl.querySelector('.join-preview-wrap');
          if (previewWrap) previewWrap.parentNode.insertBefore(cardWrap, previewWrap);
          else containerEl.appendChild(cardWrap);
        }
        if (window.CardinalityDetector && dsAIdx >= 0 && dsBIdx >= 0) {
          var datasets = getDatasets();
          var _dA = datasets[dsAIdx];
          var _dB = datasets[dsBIdx];
          var _kA = containerEl.querySelector('#join-key-a') && containerEl.querySelector('#join-key-a').value;
          var _kB = containerEl.querySelector('#join-key-b') && containerEl.querySelector('#join-key-b').value;
          if (_dA && _dB && _kA && _kB) {
            var cardAnalysis = CardinalityDetector.analyze(_dA, _dB, _kA, _kB);
            CardinalityDetector.renderWarning(cardAnalysis, cardWrap);
          }
        }
      }

      // ── Event wiring ───────────────────────────────────────────────────────
      var selA = containerEl.querySelector('#join-ds-a');
      var selB = containerEl.querySelector('#join-ds-b');

      selA.addEventListener('change', function () { populateKeys(+selA.value, +selB.value); });
      selB.addEventListener('change', function () { populateKeys(+selA.value, +selB.value); });

      containerEl.querySelectorAll('#join-key-a, #join-key-b').forEach(function (sel) {
        sel.addEventListener('change', function () { updatePreview(+selA.value, +selB.value); });
      });

      containerEl.querySelectorAll('.join-type-btn').forEach(function (btn) {
        btn.addEventListener('click', function () {
          containerEl.querySelectorAll('.join-type-btn').forEach(function (b) { b.classList.remove('active'); });
          btn.classList.add('active');
          currentJoinType = btn.dataset.type;
          updateVenn(currentJoinType);
          updatePreview(+selA.value, +selB.value);
        });
      });

      containerEl.querySelector('#join-run-btn').addEventListener('click', function () {
        var table = containerEl.querySelector('#join-preview-table');
        var result = table && table._result;
        if (!result) return;
        if (typeof onJoinComplete === 'function') onJoinComplete(result);
      });

      // Initial population
      populateKeys(defaultA, defaultB);
    }

    rebuild();

    // Return rebuild so caller can refresh when a new dataset loads
    return { refresh: rebuild };
  }

  // ── Venn diagram (SVG) ─────────────────────────────────────────────────────
  function updateVenn(type) {
    var venn = document.getElementById('join-venn');
    if (!venn) return;
    var fills = {
      inner: ['none', 'none', '#20808D44'],
      left:  ['#20808D44', 'none', '#20808D44'],
      right: ['none', '#20808D44', '#20808D44'],
      full:  ['#20808D44', '#20808D44', '#20808D44']
    }[type] || ['none','none','#20808D44'];

    venn.innerHTML = '<svg width="80" height="40" viewBox="0 0 80 40" fill="none" xmlns="http://www.w3.org/2000/svg">' +
      '<circle cx="25" cy="20" r="18" fill="' + fills[0] + '" stroke="#20808D" stroke-width="1.5"/>' +
      '<circle cx="55" cy="20" r="18" fill="' + fills[1] + '" stroke="#20808D" stroke-width="1.5"/>' +
      '<clipPath id="vcp"><circle cx="55" cy="20" r="18"/></clipPath>' +
      '<circle cx="25" cy="20" r="18" fill="' + fills[2] + '" clip-path="url(#vcp)"/>' +
      '</svg>';
  }

  function escHtml(s) {
    return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }

  return { render: render, suggestKey: suggestKey };
})();
  /* ---- end join-builder.js ---- */
  /* ---- from js/anomaly/anomaly-timeline.js ---- */
/**
 * anomaly-timeline.js — DataGlow Anomaly Timeline (PR AM)
 *
 * Pinpoints exactly when a metric changed — the exact row/date where
 * a value spiked, dropped, went missing, or crossed a threshold.
 *
 * Public API:
 *   AnomalyTimeline.detect(dataset)   → AnomalyReport
 *   AnomalyTimeline.render(report, containerEl)
 *
 * AnomalyReport: { events: AnomalyEvent[], summary: string }
 * AnomalyEvent:  { type, col, rowIndex, value, expected, delta, deltaPercent, severity, label, description }
 */

var AnomalyTimeline = (function () {
  'use strict';

  var SEV = { critical: 0, high: 1, medium: 2, low: 3 };

  // ── helpers ───────────────────────────────────────────────────────────────
  function isNum(v) { return v !== null && v !== undefined && v !== '' && !isNaN(parseFloat(v)) && isFinite(v); }
  function num(v)   { return parseFloat(v); }
  function mean(arr) { return arr.reduce(function (s, x) { return s + x; }, 0) / arr.length; }
  function stddev(arr, avg) {
    var m = avg !== undefined ? avg : mean(arr);
    return Math.sqrt(arr.reduce(function (s, x) { return s + (x - m) * (x - m); }, 0) / arr.length);
  }
  function fmt(n) {
    if (Math.abs(n) >= 1e6) return (n / 1e6).toFixed(1) + 'M';
    if (Math.abs(n) >= 1e3) return (n / 1e3).toFixed(1) + 'K';
    return parseFloat(n.toFixed(2)).toString();
  }
  function pct(n) { return (n >= 0 ? '+' : '') + (n * 100).toFixed(1) + '%'; }

  // ── numeric spike/drop detector ───────────────────────────────────────────
  function detectNumericAnomalies(rows, col, events) {
    var vals = rows.map(function (r) { return r[col]; });
    var nums = vals.map(function (v, i) { return isNum(v) ? { i: i, v: num(v) } : null; }).filter(Boolean);
    if (nums.length < 5) return;

    var values = nums.map(function (n) { return n.v; });
    var avg = mean(values);
    var sd  = stddev(values, avg);
    if (sd === 0) return; // constant  -  no anomalies

    // Z-score each value
    nums.forEach(function (n) {
      var z = (n.v - avg) / sd;
      if (Math.abs(z) < 2.5) return; // below threshold
      var severity = Math.abs(z) >= 4 ? 'critical' : Math.abs(z) >= 3 ? 'high' : 'medium';
      var direction = n.v > avg ? 'spike' : 'drop';
      events.push({
        type: direction,
        col: col,
        rowIndex: n.i,
        value: n.v,
        expected: avg,
        delta: n.v - avg,
        deltaPercent: (n.v - avg) / Math.abs(avg),
        severity: severity,
        label: direction === 'spike' ? 'Spike' : 'Drop',
        description: col + ' row ' + (n.i + 1) + ': ' + fmt(n.v) +
          ' (' + pct((n.v - avg) / Math.abs(avg)) + ' vs avg ' + fmt(avg) + ')'
      });
    });

    // Rate-of-change: consecutive jumps > 3× average step
    var steps = [];
    for (var i = 1; i < nums.length; i++) {
      steps.push({ i: nums[i].i, delta: Math.abs(nums[i].v - nums[i - 1].v), from: nums[i - 1].v, to: nums[i].v });
    }
    if (steps.length < 3) return;
    var stepVals = steps.map(function (s) { return s.delta; });
    var stepAvg = mean(stepVals);
    var stepSd  = stddev(stepVals, stepAvg);
    if (stepSd === 0) return;
    steps.forEach(function (s) {
      var z = (s.delta - stepAvg) / stepSd;
      if (z < 3) return;
      events.push({
        type: 'jump',
        col: col,
        rowIndex: s.i,
        value: s.to,
        expected: s.from,
        delta: s.to - s.from,
        deltaPercent: (s.to - s.from) / (Math.abs(s.from) || 1),
        severity: z >= 4 ? 'high' : 'medium',
        label: 'Sudden change',
        description: col + ' row ' + (s.i + 1) + ': changed ' + fmt(s.from) + ' → ' + fmt(s.to) +
          ' (' + pct((s.to - s.from) / (Math.abs(s.from) || 1)) + ')'
      });
    });
  }

  // ── missing value cluster detector ────────────────────────────────────────
  function detectMissingClusters(rows, col, events) {
    var runStart = -1, runLen = 0;
    rows.forEach(function (r, i) {
      var empty = r[col] === null || r[col] === undefined || r[col] === '';
      if (empty) {
        if (runStart === -1) runStart = i;
        runLen++;
      } else {
        if (runLen >= 3) {
          events.push({
            type: 'missing_cluster',
            col: col,
            rowIndex: runStart,
            value: null,
            expected: '(values)',
            delta: runLen,
            deltaPercent: runLen / rows.length,
            severity: runLen >= 10 ? 'high' : 'medium',
            label: 'Missing cluster',
            description: col + ': ' + runLen + ' consecutive blank values starting at row ' + (runStart + 1)
          });
        }
        runStart = -1; runLen = 0;
      }
    });
  }

  // ── duplicate row detector ────────────────────────────────────────────────
  function detectDuplicateRows(rows, events) {
    var seen = {};
    var dupeRows = [];
    rows.forEach(function (r, i) {
      var key = JSON.stringify(r);
      if (seen[key] !== undefined) {
        dupeRows.push({ i: i, origIdx: seen[key] });
      } else {
        seen[key] = i;
      }
    });
    if (dupeRows.length > 0) {
      events.push({
        type: 'duplicate',
        col: null,
        rowIndex: dupeRows[0].i,
        value: dupeRows.length,
        expected: 0,
        delta: dupeRows.length,
        deltaPercent: dupeRows.length / rows.length,
        severity: dupeRows.length >= 5 ? 'high' : 'medium',
        label: 'Duplicate rows',
        description: dupeRows.length + ' exact duplicate row' + (dupeRows.length === 1 ? '' : 's') +
          ' found (first at row ' + (dupeRows[0].i + 1) + ')'
      });
    }
  }

  // ── date gap detector ─────────────────────────────────────────────────────
  function detectDateGaps(rows, col, events) {
    var pairs = rows.map(function (r, i) {
      var d = new Date(r[col]);
      return isNaN(d) ? null : { i: i, d: d };
    }).filter(Boolean);
    if (pairs.length < 4) return;
    pairs.sort(function (a, b) { return a.d - b.d; });

    var gaps = [];
    for (var i = 1; i < pairs.length; i++) {
      var gapDays = (pairs[i].d - pairs[i - 1].d) / 86400000;
      gaps.push(gapDays);
    }
    var avgGap = mean(gaps);
    var sdGap  = stddev(gaps, avgGap);
    if (sdGap === 0 || avgGap === 0) return;

    for (var j = 0; j < gaps.length; j++) {
      var z = (gaps[j] - avgGap) / sdGap;
      if (z > 2.5) {
        events.push({
          type: 'date_gap',
          col: col,
          rowIndex: pairs[j + 1].i,
          value: gaps[j],
          expected: avgGap,
          delta: gaps[j] - avgGap,
          deltaPercent: (gaps[j] - avgGap) / avgGap,
          severity: z >= 4 ? 'high' : 'medium',
          label: 'Date gap',
          description: col + ': unusually large gap of ' + Math.round(gaps[j]) + ' days before row ' + (pairs[j + 1].i + 1) +
            ' (avg gap: ' + Math.round(avgGap) + ' days)'
        });
      }
    }
  }

  // ── categorical shift detector ────────────────────────────────────────────
  function detectCategoricalShift(rows, col, events) {
    if (rows.length < 20) return;
    var half = Math.floor(rows.length / 2);
    var firstHalf  = rows.slice(0, half);
    var secondHalf = rows.slice(half);

    var freq = function (arr) {
      var f = {};
      arr.forEach(function (r) { var k = String(r[col] || ''); f[k] = (f[k] || 0) + 1; });
      return f;
    };
    var f1 = freq(firstHalf), f2 = freq(secondHalf);
    var allKeys = new Set(Object.keys(f1).concat(Object.keys(f2)));

    allKeys.forEach(function (k) {
      var p1 = (f1[k] || 0) / half;
      var p2 = (f2[k] || 0) / half;
      var shift = Math.abs(p2 - p1);
      if (shift > 0.25 && (p1 > 0.05 || p2 > 0.05)) {
        events.push({
          type: 'category_shift',
          col: col,
          rowIndex: half,
          value: p2,
          expected: p1,
          delta: p2 - p1,
          deltaPercent: p1 > 0 ? (p2 - p1) / p1 : 1,
          severity: shift > 0.4 ? 'high' : 'medium',
          label: 'Category shift',
          description: '"' + k + '" in ' + col + ': ' + Math.round(p1 * 100) + '% → ' + Math.round(p2 * 100) + '% across dataset halves'
        });
      }
    });
  }

  // ── main detect ───────────────────────────────────────────────────────────
  function detect(dataset) {
    if (!dataset || !dataset.rows || dataset.rows.length < 3) {
      return { events: [], summary: 'Not enough data to analyze.' };
    }

    var events = [];
    var rows = dataset.rows;

    // Classify columns
    var numCols = [], dateCols = [], catCols = [];
    dataset.columns.forEach(function (col) {
      var name = col.name;
      var sample = rows.slice(0, 30).map(function (r) { return r[name]; });
      var numCount = sample.filter(isNum).length;
      var dateCount = sample.filter(function (v) {
        return v && /^\d{4}[-/]/.test(String(v));
      }).length;
      if (numCount >= sample.length * 0.6) numCols.push(name);
      else if (dateCount >= 3) dateCols.push(name);
      else catCols.push(name);
    });

    // Run detectors
    numCols.forEach(function (c) { detectNumericAnomalies(rows, c, events); });
    dataset.columns.forEach(function (col) { detectMissingClusters(rows, col.name, events); });
    detectDuplicateRows(rows, events);
    dateCols.forEach(function (c) { detectDateGaps(rows, c, events); });
    catCols.slice(0, 3).forEach(function (c) { detectCategoricalShift(rows, c, events); });

    // Sort by severity then rowIndex
    events.sort(function (a, b) {
      var sd = SEV[a.severity] - SEV[b.severity];
      return sd !== 0 ? sd : (a.rowIndex || 0) - (b.rowIndex || 0);
    });

    // Cap to 30 most significant
    events = events.slice(0, 30);

    var critCount = events.filter(function (e) { return e.severity === 'critical'; }).length;
    var highCount = events.filter(function (e) { return e.severity === 'high'; }).length;
    var summary = events.length === 0
      ? 'No anomalies detected. Your data looks clean.'
      : events.length + ' anomal' + (events.length === 1 ? 'y' : 'ies') + ' found' +
        (critCount ? '  -  ' + critCount + ' critical' : '') +
        (highCount ? ', ' + highCount + ' high-severity' : '') + '.';

    return { events: events, summary: summary };
  }

  // ── render ─────────────────────────────────────────────────────────────────
  function render(report, containerEl) {
    containerEl.innerHTML = '';

    var header = document.createElement('div');
    header.className = 'anom-header';
    var dot = report.events.length === 0 ? 'anom-dot-ok' :
              report.events.some(function (e) { return e.severity === 'critical'; }) ? 'anom-dot-crit' :
              report.events.some(function (e) { return e.severity === 'high'; })     ? 'anom-dot-high' : 'anom-dot-med';
    header.innerHTML = '<span class="anom-dot ' + dot + '"></span><span class="anom-summary">' + escHtml(report.summary) + '</span>';
    containerEl.appendChild(header);

    if (!report.events.length) return;

    var timeline = document.createElement('div');
    timeline.className = 'anom-timeline';

    report.events.forEach(function (ev) {
      var item = document.createElement('div');
      item.className = 'anom-item anom-sev-' + ev.severity;
      item.dataset.rowIndex = ev.rowIndex || 0;

      var badge = document.createElement('span');
      badge.className = 'anom-badge';
      badge.textContent = ev.label;

      var desc = document.createElement('span');
      desc.className = 'anom-desc';
      desc.textContent = ev.description;

      var row = document.createElement('span');
      row.className = 'anom-row-ref';
      if (ev.rowIndex != null) row.textContent = 'Row ' + (ev.rowIndex + 1);

      item.appendChild(badge);
      item.appendChild(desc);
      item.appendChild(row);
      timeline.appendChild(item);
    });

    containerEl.appendChild(timeline);
  }

  function escHtml(s) {
    return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  }

  return { detect: detect, render: render };
})();
  /* ---- end anomaly-timeline.js ---- */
  /* ---- from js/grid/canvas-grid.js ---- */
/**
 * canvas-grid.js — DataGlow High-Performance Canvas Grid (PR AO)
 *
 * Pure HTML5 Canvas grid renderer. No DOM nodes per cell. No React.
 * Zero dependencies. Renders 1M+ rows at 60fps via virtual scrolling.
 *
 * Architecture:
 *  - Only draws the visible viewport (typically 20-40 rows)
 *  - Virtual scroll: scrollTop/scrollLeft determine which rows/cols to draw
 *  - Canvas is resized to fill container via ResizeObserver
 *  - Header drawn on a separate sticky canvas above the main canvas
 *  - Row flags (warning/error) drawn as left-border colored stripes
 *  - Health dots drawn in column headers
 *  - Column widths are measured from data samples on first render
 *  - Click → row selection + opens validation rail (same as DOM grid)
 *  - Double-click header → triggers ColumnEditor rename (same as DOM grid)
 *  - Formula bar wired to show active cell value
 *
 * Public API:
 *   CanvasGrid.mount(containerEl, dataset, opts) → instance
 *   instance.update(dataset)    — swap to new dataset, re-render
 *   instance.destroy()          — remove canvases, cancel RAF
 *   instance.getActiveCell()    → { row, col } or null
 *   instance.scrollToRow(idx)
 */

var CanvasGrid = (function () {
  'use strict';

  // ── Design tokens (keep in sync with CSS vars) ────────────────────────────
  function getTokens(isDark) {
    return isDark ? {
      bg:          '#171614',
      surface:     '#1C1B19',
      border:      '#393836',
      text:        '#CDCCCA',
      textMuted:   '#797876',
      textFaint:   '#5A5957',
      primary:     '#4F98A3',
      mono:        'Consolas, "Courier New", monospace',
      sans:        'system-ui, -apple-system, sans-serif',
      rowAlt:      '#1C1B19',
      rowHover:    '#20201E',
      rowSelected: '#1B3A3D',
      rowWarning:  'rgba(217,119,6,0.07)',
      rowError:    'rgba(185,28,28,0.07)',
      flagWarning: '#D97706',
      flagError:   '#DC2626',
      flagGreen:   '#16A34A',
      flagAmber:   '#D97706',
      flagRed:     '#DC2626',
      headerBg:    '#201F1D',
      headerBorder:'#393836',
      chipBg:      '#171614',
      chipBorder:  '#393836',
      chipText:    '#797876',
      emptyText:   '#5A5957',
      scrollThumb: '#393836',
    } : {
      bg:          '#F7F6F2',
      surface:     '#F9F8F5',
      border:      '#D4D1CA',
      text:        '#28251D',
      textMuted:   '#7A7974',
      textFaint:   '#BAB9B4',
      primary:     '#01696F',
      mono:        'Consolas, "Courier New", monospace',
      sans:        'system-ui, -apple-system, sans-serif',
      rowAlt:      '#FAFAF8',
      rowHover:    '#F0EFE9',
      rowSelected: '#E0F0F1',
      rowWarning:  'rgba(217,119,6,0.06)',
      rowError:    'rgba(185,28,28,0.06)',
      flagWarning: '#D97706',
      flagError:   '#DC2626',
      flagGreen:   '#16A34A',
      flagAmber:   '#D97706',
      flagRed:     '#DC2626',
      headerBg:    '#F2F1ED',
      headerBorder:'#D4D1CA',
      chipBg:      '#F7F6F2',
      chipBorder:  '#D4D1CA',
      chipText:    '#7A7974',
      emptyText:   '#BAB9B4',
      scrollThumb: '#D4D1CA',
    };
  }

  // ── Constants ─────────────────────────────────────────────────────────────
  var ROW_H        = 34;    // px per data row
  var HEADER_H     = 40;    // px for column header
  var FLAG_W       = 3;     // px left border for row flags
  var MIN_COL_W    = 80;
  var MAX_COL_W    = 320;
  var PAD_H        = 12;    // horizontal cell padding
  var PAD_V        = 10;    // vertical cell padding
  var FONT_CELL    = '13px system-ui,-apple-system,sans-serif';
  var FONT_HEADER  = '600 13px system-ui,-apple-system,sans-serif';
  var FONT_CHIP    = '10px Consolas,"Courier New",monospace';
  var FONT_EMPTY   = 'italic 13px system-ui,-apple-system,sans-serif';
  var SCROLL_BAR_W = 12;    // virtual scrollbar width
  var OVERDRAW     = 2;     // extra rows drawn above/below viewport

  // ── Column width measurement ──────────────────────────────────────────────
  function measureColWidths(ctx, dataset) {
    var cols = dataset.columns, rows = dataset.rows;
    return cols.map(function (col, ci) {
      // Measure header: name + type chip
      ctx.font = FONT_HEADER;
      var hw = ctx.measureText(col.name).width + 60; // 60 for chip + dot + padding
      // Sample up to 30 rows
      ctx.font = FONT_CELL;
      var maxSample = Math.min(rows.length, 30);
      var mw = hw;
      for (var ri = 0; ri < maxSample; ri++) {
        var v = rows[ri][ci];
        var s = (v === null || v === undefined || v === '') ? '' : String(v);
        var w = ctx.measureText(s).width + PAD_H * 2 + FLAG_W;
        if (w > mw) mw = w;
      }
      return Math.max(MIN_COL_W, Math.min(MAX_COL_W, mw));
    });
  }

  // ── Helpers ───────────────────────────────────────────────────────────────
  function isDarkMode() {
    return document.documentElement.classList.contains('dark');
  }

  function clamp(v, lo, hi) { return Math.max(lo, Math.min(hi, v)); }

  function formatCell(v) {
    if (v === null || v === undefined || v === '') return null; // null = render as empty
    return String(v);
  }

  function colHealthColor(dataset, colIdx, tok) {
    if (!dataset.columnHealth) return tok.flagGreen;
    var h = dataset.columnHealth[colIdx];
    if (h === 'red')   return tok.flagRed;
    if (h === 'amber') return tok.flagAmber;
    return tok.flagGreen;
  }

  // ── Canvas Grid Instance ──────────────────────────────────────────────────
  function create(container, dataset, opts) {
    opts = opts || {};
    var onRowClick   = opts.onRowClick   || function () {};
    var onColDblClick= opts.onColDblClick|| function () {};
    var onCellFocus  = opts.onCellFocus  || function () {};

    // Wrapper takes full container space
    var wrapper = document.createElement('div');
    wrapper.style.cssText = 'position:relative;width:100%;height:100%;overflow:hidden;';

    // Header canvas (sticky, top)
    var headerCanvas = document.createElement('canvas');
    headerCanvas.style.cssText = 'display:block;position:absolute;top:0;left:0;z-index:2;';

    // Main canvas (scrollable content)
    var mainCanvas = document.createElement('canvas');
    mainCanvas.style.cssText = 'display:block;position:absolute;top:'+HEADER_H+'px;left:0;';
    mainCanvas.setAttribute('tabindex', '0');

    // Virtual scrollbar div (thin overlay on right edge)
    var vScroll = document.createElement('div');
    vScroll.style.cssText = 'position:absolute;right:0;top:'+HEADER_H+'px;width:'+SCROLL_BAR_W+'px;overflow-y:scroll;overflow-x:hidden;z-index:3;';
    var vScrollInner = document.createElement('div');
    vScrollInner.style.cssText = 'width:1px;';
    vScroll.appendChild(vScrollInner);

    var hScroll = document.createElement('div');
    hScroll.style.cssText = 'position:absolute;bottom:0;left:0;right:'+SCROLL_BAR_W+'px;height:'+SCROLL_BAR_W+'px;overflow-x:scroll;overflow-y:hidden;z-index:3;';
    var hScrollInner = document.createElement('div');
    hScrollInner.style.cssText = 'height:1px;';
    hScroll.appendChild(hScrollInner);

    wrapper.appendChild(headerCanvas);
    wrapper.appendChild(mainCanvas);
    wrapper.appendChild(vScroll);
    wrapper.appendChild(hScroll);
    container.innerHTML = '';
    container.appendChild(wrapper);

    var hCtx = headerCanvas.getContext('2d');
    var mCtx = mainCanvas.getContext('2d');

    var state = {
      dataset:     dataset,
      colWidths:   [],
      totalW:      0,
      totalH:      0,
      scrollTop:   0,
      scrollLeft:  0,
      activeRow:   -1,
      activeCol:   -1,
      hoverRow:    -1,
      width:       0,    // canvas draw width (CSS pixels)
      height:      0,    // main canvas draw height
      dpr:         window.devicePixelRatio || 1,
      rafId:       null,
      dirty:       true,
    };

    function initColWidths() {
      // Use offscreen canvas for measurement (no draw side effects)
      var mc = document.createElement('canvas');
      var mx = mc.getContext('2d');
      state.colWidths = measureColWidths(mx, state.dataset);
      state.totalW = state.colWidths.reduce(function (s, w) { return s + w; }, 0) + FLAG_W;
      state.totalH = state.dataset.rows.length * ROW_H;
    }

    function resize() {
      var rect = container.getBoundingClientRect();
      var dpr  = window.devicePixelRatio || 1;
      var w    = Math.floor(rect.width);
      var h    = Math.floor(rect.height);
      state.width  = w;
      state.height = h - HEADER_H - SCROLL_BAR_W;
      state.dpr    = dpr;

      // Header canvas
      headerCanvas.width  = w * dpr;
      headerCanvas.height = HEADER_H * dpr;
      headerCanvas.style.width  = w + 'px';
      headerCanvas.style.height = HEADER_H + 'px';
      hCtx.scale(dpr, dpr);

      // Main canvas
      mainCanvas.width  = w * dpr;
      mainCanvas.height = state.height * dpr;
      mainCanvas.style.width  = w + 'px';
      mainCanvas.style.height = state.height + 'px';
      mCtx.scale(dpr, dpr);

      // Virtual scrollbar heights
      vScroll.style.height = state.height + 'px';
      vScrollInner.style.height = state.totalH + 'px';
      hScrollInner.style.width  = state.totalW + 'px';

      state.dirty = true;
    }

    // ── Draw header ──────────────────────────────────────────────────────
    function drawHeader() {
      var tok  = getTokens(isDarkMode());
      var ctx  = hCtx;
      var w    = state.width;
      var cols = state.dataset.columns;
      var dpr  = state.dpr;

      ctx.save();
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

      // Background
      ctx.fillStyle = tok.headerBg;
      ctx.fillRect(0, 0, w, HEADER_H);

      // Bottom border
      ctx.fillStyle = tok.headerBorder;
      ctx.fillRect(0, HEADER_H - 1, w, 1);

      var x = FLAG_W - state.scrollLeft;

      cols.forEach(function (col, ci) {
        var cw = state.colWidths[ci];
        if (x + cw < 0 || x > w) { x += cw; return; }

        // Column right border
        ctx.fillStyle = tok.border;
        ctx.fillRect(x + cw - 1, 0, 1, HEADER_H - 1);

        // Clip to column
        ctx.save();
        ctx.beginPath();
        ctx.rect(Math.max(FLAG_W, x), 0, cw - 1, HEADER_H);
        ctx.clip();

        // Column name
        ctx.font = FONT_HEADER;
        ctx.fillStyle = tok.text;
        ctx.textBaseline = 'middle';
        ctx.fillText(col.name, x + PAD_H, HEADER_H / 2 - 5);

        // Type chip
        var chipText = col.type || 'STR';
        ctx.font = FONT_CHIP;
        var chipW = ctx.measureText(chipText).width + 8;
        var chipX = x + PAD_H;
        var chipY = HEADER_H / 2 + 6;

        ctx.fillStyle = tok.chipBg;
        ctx.strokeStyle = tok.chipBorder;
        ctx.lineWidth = 1;
        roundRect(ctx, chipX - 1, chipY - 8, chipW + 2, 14, 3);
        ctx.fill();
        ctx.stroke();

        ctx.fillStyle = tok.chipText;
        ctx.textBaseline = 'middle';
        ctx.fillText(chipText, chipX + 3, chipY);

        // Health dot
        var dotColor = colHealthColor(state.dataset, ci, tok);
        var dotX = x + cw - 18;
        var dotY = HEADER_H / 2;
        ctx.beginPath();
        ctx.arc(dotX, dotY, 4, 0, Math.PI * 2);
        ctx.fillStyle = dotColor;
        ctx.fill();

        ctx.restore();
        x += cw;
      });

      ctx.restore();
    }

    // ── Draw main grid ───────────────────────────────────────────────────
    function drawGrid() {
      var tok    = getTokens(isDarkMode());
      var ctx    = mCtx;
      var w      = state.width;
      var h      = state.height;
      var rows   = state.dataset.rows;
      var cols   = state.dataset.columns;
      var flags  = state.dataset.rowFlags || [];
      var dpr    = state.dpr;

      ctx.save();
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

      // Background
      ctx.fillStyle = tok.bg;
      ctx.fillRect(0, 0, w, h);

      var firstRow = Math.max(0, Math.floor(state.scrollTop / ROW_H) - OVERDRAW);
      var lastRow  = Math.min(rows.length - 1, Math.ceil((state.scrollTop + h) / ROW_H) + OVERDRAW);

      for (var ri = firstRow; ri <= lastRow; ri++) {
        var y    = ri * ROW_H - state.scrollTop;
        var row  = rows[ri];
        var flag = flags[ri] || {};
        var isActive  = ri === state.activeRow;
        var isHovered = ri === state.hoverRow;

        // Row background
        var rowBg;
        if (isActive)       rowBg = tok.rowSelected;
        else if (isHovered) rowBg = tok.rowHover;
        else if (flag.error)   rowBg = tok.rowError;
        else if (flag.warning) rowBg = tok.rowWarning;
        else if (ri % 2 === 0) rowBg = tok.bg;
        else                   rowBg = tok.rowAlt;

        ctx.fillStyle = rowBg;
        ctx.fillRect(0, y, w, ROW_H);

        // Row flag stripe (left edge)
        if (flag.error) {
          ctx.fillStyle = tok.flagError;
          ctx.fillRect(0, y, FLAG_W, ROW_H);
        } else if (flag.warning) {
          ctx.fillStyle = tok.flagWarning;
          ctx.fillRect(0, y, FLAG_W, ROW_H);
        }

        // Row bottom divider
        ctx.fillStyle = tok.border;
        ctx.globalAlpha = 0.4;
        ctx.fillRect(0, y + ROW_H - 1, w, 1);
        ctx.globalAlpha = 1;

        // Cells
        var x = FLAG_W - state.scrollLeft;
        cols.forEach(function (col, ci) {
          var cw  = state.colWidths[ci];
          if (x + cw < 0 || x > w) { x += cw; return; }

          // Column divider
          ctx.fillStyle = tok.border;
          ctx.globalAlpha = 0.35;
          ctx.fillRect(x + cw - 1, y, 1, ROW_H);
          ctx.globalAlpha = 1;

          // Cell value
          var raw = row ? row[ci] : undefined;
          var txt = formatCell(raw);

          ctx.save();
          ctx.beginPath();
          ctx.rect(Math.max(FLAG_W, x + 1), y, cw - 2, ROW_H - 1);
          ctx.clip();

          if (txt === null) {
            ctx.font = FONT_EMPTY;
            ctx.fillStyle = tok.emptyText;
            ctx.textBaseline = 'middle';
            ctx.fillText('\u2014', x + PAD_H, y + ROW_H / 2);
          } else {
            ctx.font = FONT_CELL;
            ctx.fillStyle = (isActive && ci === state.activeCol) ? tok.primary : tok.text;
            ctx.textBaseline = 'middle';
            ctx.fillText(txt, x + PAD_H, y + ROW_H / 2);
          }

          ctx.restore();
          x += cw;
        });
      }

      // Empty state
      if (rows.length === 0) {
        ctx.font = '14px system-ui,-apple-system,sans-serif';
        ctx.fillStyle = tok.textMuted;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText('No data loaded', w / 2, h / 2);
        ctx.textAlign = 'left';
      }

      ctx.restore();
    }

    // ── Rounded rect helper ──────────────────────────────────────────────
    function roundRect(ctx, x, y, w, h, r) {
      ctx.beginPath();
      ctx.moveTo(x + r, y);
      ctx.lineTo(x + w - r, y);
      ctx.quadraticCurveTo(x + w, y, x + w, y + r);
      ctx.lineTo(x + w, y + h - r);
      ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
      ctx.lineTo(x + r, y + h);
      ctx.quadraticCurveTo(x, y + h, x, y + h - r);
      ctx.lineTo(x, y + r);
      ctx.quadraticCurveTo(x, y, x + r, y);
      ctx.closePath();
    }

    // ── RAF render loop ──────────────────────────────────────────────────
    function renderLoop() {
      if (state.dirty) {
        drawHeader();
        drawGrid();
        state.dirty = false;
      }
      state.rafId = requestAnimationFrame(renderLoop);
    }

    // ── Scroll sync ──────────────────────────────────────────────────────
    vScroll.addEventListener('scroll', function () {
      state.scrollTop = vScroll.scrollTop;
      headerCanvas.style.left = '0px'; // header doesn't scroll vertically
      state.dirty = true;
    }, { passive: true });

    hScroll.addEventListener('scroll', function () {
      state.scrollLeft = hScroll.scrollLeft;
      state.dirty = true;
    }, { passive: true });

    // Also allow wheel on main canvas
    mainCanvas.addEventListener('wheel', function (e) {
      e.preventDefault();
      vScroll.scrollTop  += e.deltaY;
      hScroll.scrollLeft += e.deltaX;
    }, { passive: false });

    // ── Mouse events ──────────────────────────────────────────────────────
    function rowFromY(y) {
      return Math.floor((y + state.scrollTop) / ROW_H);
    }

    function colFromX(x) {
      var cx = FLAG_W - state.scrollLeft;
      for (var ci = 0; ci < state.colWidths.length; ci++) {
        cx += state.colWidths[ci];
        if (x < cx) return ci;
      }
      return state.colWidths.length - 1;
    }

    mainCanvas.addEventListener('mousemove', function (e) {
      var rect = mainCanvas.getBoundingClientRect();
      var ri = rowFromY(e.clientY - rect.top);
      if (ri !== state.hoverRow) {
        state.hoverRow = ri;
        state.dirty = true;
      }
    });

    mainCanvas.addEventListener('mouseleave', function () {
      state.hoverRow = -1;
      state.dirty = true;
    });

    mainCanvas.addEventListener('click', function (e) {
      var rect = mainCanvas.getBoundingClientRect();
      var ri = rowFromY(e.clientY - rect.top);
      var ci = colFromX(e.clientX - rect.left);
      if (ri >= 0 && ri < state.dataset.rows.length) {
        state.activeRow = ri;
        state.activeCol = ci;
        state.dirty = true;
        var raw = state.dataset.rows[ri][ci];
        onCellFocus({ row: ri, col: ci, value: raw, colName: (state.dataset.columns[ci] || {}).name });
        onRowClick(state.dataset, ri);
      }
    });

    // Header double-click → rename column
    headerCanvas.addEventListener('dblclick', function (e) {
      var rect = headerCanvas.getBoundingClientRect();
      var x = e.clientX - rect.left + state.scrollLeft - FLAG_W;
      var cx = 0;
      for (var ci = 0; ci < state.colWidths.length; ci++) {
        cx += state.colWidths[ci];
        if (x < cx) { onColDblClick(ci); return; }
      }
    });

    // ── Keyboard navigation ───────────────────────────────────────────────
    mainCanvas.addEventListener('keydown', function (e) {
      var rows = state.dataset.rows;
      var cols = state.dataset.columns;
      if (!rows.length) return;

      var ar = state.activeRow < 0 ? 0 : state.activeRow;
      var ac = state.activeCol < 0 ? 0 : state.activeCol;

      switch (e.key) {
        case 'ArrowDown':  ar = Math.min(rows.length - 1, ar + 1); e.preventDefault(); break;
        case 'ArrowUp':    ar = Math.max(0, ar - 1); e.preventDefault(); break;
        case 'ArrowRight': ac = Math.min(cols.length - 1, ac + 1); e.preventDefault(); break;
        case 'ArrowLeft':  ac = Math.max(0, ac - 1); e.preventDefault(); break;
        case 'Home':       ar = 0; e.preventDefault(); break;
        case 'End':        ar = rows.length - 1; e.preventDefault(); break;
        default: return;
      }

      state.activeRow = ar;
      state.activeCol = ac;

      // Auto-scroll to keep active row visible
      var rowTop = ar * ROW_H;
      var rowBot = rowTop + ROW_H;
      if (rowTop < state.scrollTop)
        vScroll.scrollTop = rowTop;
      else if (rowBot > state.scrollTop + state.height)
        vScroll.scrollTop = rowBot - state.height;

      var raw = rows[ar][ac];
      onCellFocus({ row: ar, col: ac, value: raw, colName: (cols[ac] || {}).name });
      state.dirty = true;
    });

    // ── ResizeObserver ────────────────────────────────────────────────────
    var ro = new ResizeObserver(function () {
      resize();
    });
    ro.observe(container);

    // ── Init ──────────────────────────────────────────────────────────────
    function init(ds) {
      state.dataset   = ds;
      state.scrollTop = 0;
      state.scrollLeft= 0;
      state.activeRow = -1;
      state.activeCol = -1;
      state.hoverRow  = -1;
      initColWidths();
      resize();
      vScrollInner.style.height = state.totalH + 'px';
      hScrollInner.style.width  = state.totalW + 'px';
      state.dirty = true;
    }

    init(dataset);
    renderLoop();

    // ── Watch for dark mode changes ───────────────────────────────────────
    var darkObserver = new MutationObserver(function () {
      state.dirty = true;
    });
    darkObserver.observe(document.documentElement, { attributes: true, attributeFilter: ['class'] });

    // ── Public API ────────────────────────────────────────────────────────
    return {
      update: function (ds) { init(ds); },
      destroy: function () {
        if (state.rafId) cancelAnimationFrame(state.rafId);
        ro.disconnect();
        darkObserver.disconnect();
        container.innerHTML = '';
      },
      getActiveCell: function () {
        if (state.activeRow < 0) return null;
        return { row: state.activeRow, col: state.activeCol };
      },
      scrollToRow: function (idx) {
        vScroll.scrollTop = Math.max(0, idx * ROW_H - state.height / 2);
      },
      markDirty: function () { state.dirty = true; }
    };
  }

  return { mount: create };
})();

  /* ---- end canvas-grid.js ---- */

  /* ---- from js/sql/sql-engine.js ---- */
/**
 * sql-engine.js — DataGlow Real SQL Engine (PR AO)
 *
 * Powers the SQL Mode overlay with real DuckDB-WASM execution,
 * smart autocomplete, query history, schema sidebar, and explain output.
 *
 * Public API:
 *   SQLEngine.init(containerEl, getDatasets, opts) → instance
 *   instance.loadDataset(dataset)   — registers dataset as DuckDB table
 *   instance.runQuery(sql)          → Promise<{columns, rows, durationMs}>
 *   instance.destroy()
 *
 * Smart features:
 *   - Schema panel: table name, column names + types at a glance
 *   - Autocomplete: column names, table name, SQL keywords, functions
 *   - Query history (last 20, navigable with ↑↓)
 *   - EXPLAIN plan toggle
 *   - Error messages translated to plain English
 *   - "Export results as CSV" after any query
 *   - AI suggestions: if query returns 0 rows, suggest a fix
 *   - Multi-dataset: each loaded file becomes its own table
 */

var SQLEngine = (function () {
  'use strict';

  // DuckDB-WASM CDN (ESM bundle  -  loads via dynamic import in init)
  var DUCKDB_CDN = 'https://cdn.jsdelivr.net/npm/@duckdb/duckdb-wasm@1.29.0/dist/duckdb-esm.js';

  var SQL_KEYWORDS = [
    'SELECT', 'FROM', 'WHERE', 'GROUP BY', 'ORDER BY', 'HAVING', 'LIMIT', 'OFFSET',
    'JOIN', 'LEFT JOIN', 'RIGHT JOIN', 'INNER JOIN', 'FULL JOIN', 'ON',
    'AND', 'OR', 'NOT', 'IN', 'BETWEEN', 'LIKE', 'IS NULL', 'IS NOT NULL',
    'AS', 'DISTINCT', 'COUNT', 'SUM', 'AVG', 'MIN', 'MAX',
    'CASE', 'WHEN', 'THEN', 'ELSE', 'END',
    'UNION', 'UNION ALL', 'INTERSECT', 'EXCEPT',
    'WITH', 'CTE', 'PARTITION BY', 'OVER', 'ROW_NUMBER', 'RANK', 'DENSE_RANK',
    'LAG', 'LEAD', 'FIRST_VALUE', 'LAST_VALUE',
    'CAST', 'TRY_CAST', 'COALESCE', 'NULLIF', 'IFF',
    'STRFTIME', 'DATE_TRUNC', 'DATE_DIFF', 'NOW', 'CURRENT_DATE',
    'ROUND', 'FLOOR', 'CEIL', 'ABS', 'MOD',
    'LOWER', 'UPPER', 'TRIM', 'LENGTH', 'SUBSTRING', 'REPLACE', 'CONCAT',
    'ARRAY_AGG', 'STRING_AGG', 'LIST_AGG',
    'ASC', 'DESC', 'NULLS FIRST', 'NULLS LAST',
    'CREATE', 'INSERT', 'UPDATE', 'DELETE', 'DROP', 'ALTER',
    'TRUE', 'FALSE', 'NULL'
  ];

  // Friendly error translations
  var ERROR_TRANSLATIONS = [
    { pattern: /Table.*not found|No table.*named/i, msg: 'Table not found. Check the table name in the Schema panel on the left.' },
    { pattern: /Column.*not found|No column.*named/i, msg: 'Column not found. Check the column names in the Schema panel.' },
    { pattern: /Syntax error/i, msg: 'SQL syntax error. Check for missing commas, unclosed parentheses, or misspelled keywords.' },
    { pattern: /division by zero/i, msg: 'Division by zero detected. Add a WHERE or NULLIF guard around your denominator.' },
    { pattern: /conversion.*failed|cannot cast/i, msg: 'Type conversion failed. A column may contain text where a number is expected.' },
    { pattern: /ambiguous.*column/i, msg: 'Ambiguous column name. Prefix it with the table name: `tablename.columnname`.' }
  ];

  function translateError(msg) {
    for (var i = 0; i < ERROR_TRANSLATIONS.length; i++) {
      if (ERROR_TRANSLATIONS[i].pattern.test(msg)) return ERROR_TRANSLATIONS[i].msg;
    }
    return msg;
  }

  // Smart query suggestions when 0 rows returned
  function zeroRowsSuggestion(sql, dataset) {
    var suggestions = [];
    if (/WHERE/i.test(sql)) {
      suggestions.push('Your WHERE clause may be too restrictive. Try removing it temporarily to see if rows exist.');
    }
    if (/LIMIT\s+0/i.test(sql)) {
      suggestions.push('LIMIT 0 returns no rows by design. Increase your LIMIT value.');
    }
    if (dataset && dataset.rows && dataset.rows.length > 0) {
      suggestions.push('The table has ' + dataset.rows.length.toLocaleString() + ' rows  -  try SELECT * FROM "' + safeTableName(dataset.name) + '" LIMIT 5 to verify access.');
    }
    return suggestions.length ? suggestions[0] : null;
  }

  function safeTableName(filename) {
    return (filename || 'dataset').replace(/\.[^.]+$/, '').replace(/[^a-zA-Z0-9_]/g, '_');
  }

  function escHtml(s) {
    return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }

  // ── DuckDB-WASM wrapper ────────────────────────────────────────────────────
  function createDuckDBAdapter() {
    var db = null, conn = null, initialised = false, registeredTables = {};

    async function ensureInit() {
      if (initialised) return;
      initialised = true;
      try {
        // Dynamic import of DuckDB-WASM ESM bundle
        /* Enterprise policy: cdnFetches disable key blocks the CDN load.
           Air-gapped deployments must vendor the DuckDB bundle alongside index.html. */
        if (window.EnterprisePolicy && window.EnterprisePolicy.isDisabled('cdnFetches')) {
          throw new Error('[DATAGLOW enterprise] CDN fetches are disabled by policy. ' +
            'Vendor the DuckDB-WASM bundle and set DUCKDB_CDN to a local path.');
        }
        var mod = await import(DUCKDB_CDN);
        var JSDELIVR_BUNDLES = mod.getJsDelivrBundles ? mod.getJsDelivrBundles() : mod.selectBundle ? mod.selectBundle(mod.getJsDelivrBundles()) : null;
        var bundle = JSDELIVR_BUNDLES || {
          mainModule: 'https://cdn.jsdelivr.net/npm/@duckdb/duckdb-wasm@1.29.0/dist/duckdb-eh.wasm',
          mainWorker: 'https://cdn.jsdelivr.net/npm/@duckdb/duckdb-wasm@1.29.0/dist/duckdb-browser-eh.worker.js'
        };
        if (mod.selectBundle) bundle = mod.selectBundle(mod.getJsDelivrBundles());
        var worker = new Worker(bundle.mainWorker);
        var logger = new mod.ConsoleLogger ? new mod.ConsoleLogger() : { log: function(){} };
        db = new mod.AsyncDuckDB(logger, worker);
        await db.instantiate(bundle.mainModule, bundle.pthreadWorker);
        conn = await db.connect();
      } catch (e) {
        db = null; conn = null; initialised = false;
        throw new Error('DuckDB-WASM failed to load: ' + e.message);
      }
    }

    async function registerDataset(dataset) {
      await ensureInit();
      var tbl = safeTableName(dataset.name);
      if (registeredTables[tbl]) return tbl; // already registered

      // Build CSV string from dataset rows
      var cols = dataset.columns.map(function (c) { return c.name; });
      var lines = [cols.map(function (c) { return JSON.stringify(String(c)); }).join(',')];
      dataset.rows.forEach(function (row) {
        lines.push(cols.map(function (c) {
          var v = row[c];
          if (v === null || v === undefined) return '';
          return JSON.stringify(String(v));
        }).join(','));
      });
      var csv = lines.join('\n');

      // Register as in-memory CSV
      var encoder = new TextEncoder();
      var bytes = encoder.encode(csv);
      var fname = tbl + '.csv';
      await db.registerFileBuffer(fname, bytes);
      await conn.query("CREATE OR REPLACE TABLE \"" + tbl + "\" AS SELECT * FROM read_csv_auto('" + fname + "', header=true)");
      registeredTables[tbl] = true;
      return tbl;
    }

    async function query(sql, datasets) {
      await ensureInit();
      // Register all datasets
      for (var i = 0; i < datasets.length; i++) {
        await registerDataset(datasets[i]);
      }
      var t0 = Date.now();
      var result = await conn.query(sql);
      var durationMs = Date.now() - t0;

      var schema = result.schema.fields;
      var columns = schema.map(function (f) { return { name: f.name, type: String(f.type) }; });
      var rows = result.toArray().map(function (r) {
        return r.toJSON ? r.toJSON() : Object.fromEntries(columns.map(function (c) { return [c.name, r[c.name]]; }));
      });
      return { columns: columns, rows: rows, durationMs: durationMs };
    }

    return { query: query, registerDataset: registerDataset };
  }

  // ── Autocomplete ──────────────────────────────────────────────────────────
  function buildAutocomplete(textarea, getSchemaTokens) {
    var dropEl = document.createElement('div');
    dropEl.className = 'sql-autocomplete';
    dropEl.style.display = 'none';
    textarea.parentNode.style.position = 'relative';
    textarea.parentNode.appendChild(dropEl);

    var items = [], activeIdx = -1;

    function getWordBefore() {
      var pos = textarea.selectionStart;
      var text = textarea.value.slice(0, pos);
      var m = /[\w"]+$/.exec(text);
      return m ? m[0] : '';
    }

    function show(matches) {
      items = matches;
      activeIdx = -1;
      if (!matches.length) { dropEl.style.display = 'none'; return; }
      dropEl.innerHTML = matches.slice(0, 8).map(function (m, i) {
        return '<div class="sql-ac-item" data-idx="' + i + '">' + escHtml(m.text) +
          (m.detail ? '<span class="sql-ac-detail">' + escHtml(m.detail) + '</span>' : '') + '</div>';
      }).join('');
      dropEl.style.display = 'block';
      dropEl.querySelectorAll('.sql-ac-item').forEach(function (el) {
        el.addEventListener('mousedown', function (e) {
          e.preventDefault();
          applyCompletion(items[+el.dataset.idx].text);
        });
      });
    }

    function hide() { dropEl.style.display = 'none'; items = []; activeIdx = -1; }

    function applyCompletion(text) {
      var pos = textarea.selectionStart;
      var before = textarea.value.slice(0, pos);
      var after = textarea.value.slice(pos);
      var m = /[\w"]+$/.exec(before);
      var start = m ? pos - m[0].length : pos;
      textarea.value = before.slice(0, start) + text + after;
      textarea.selectionStart = textarea.selectionEnd = start + text.length;
      hide();
      textarea.focus();
    }

    textarea.addEventListener('input', function () {
      var word = getWordBefore();
      if (word.length < 1) { hide(); return; }
      var tokens = getSchemaTokens();
      var all = SQL_KEYWORDS.map(function (k) { return { text: k, detail: 'keyword' }; })
        .concat(tokens.map(function (t) { return { text: t.text, detail: t.detail }; }));
      var lc = word.toLowerCase();
      var matches = all.filter(function (t) { return t.text.toLowerCase().startsWith(lc) && t.text.toLowerCase() !== lc; });
      show(matches);
    });

    textarea.addEventListener('keydown', function (e) {
      if (dropEl.style.display === 'none') return;
      if (e.key === 'ArrowDown') {
        e.preventDefault();
        activeIdx = Math.min(activeIdx + 1, Math.min(items.length, 8) - 1);
        dropEl.querySelectorAll('.sql-ac-item').forEach(function (el, i) { el.classList.toggle('active', i === activeIdx); });
      } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        activeIdx = Math.max(activeIdx - 1, 0);
        dropEl.querySelectorAll('.sql-ac-item').forEach(function (el, i) { el.classList.toggle('active', i === activeIdx); });
      } else if (e.key === 'Enter' || e.key === 'Tab') {
        if (activeIdx >= 0 && items[activeIdx]) { e.preventDefault(); applyCompletion(items[activeIdx].text); }
        else hide();
      } else if (e.key === 'Escape') {
        hide();
      }
    });

    document.addEventListener('click', function (e) { if (!dropEl.contains(e.target) && e.target !== textarea) hide(); });
  }

  // ── Query history ─────────────────────────────────────────────────────────
  function createHistory() {
    var items = [], idx = -1;
    return {
      push: function (sql) { items.unshift(sql); if (items.length > 20) items.pop(); idx = -1; },
      prev: function () { if (idx < items.length - 1) idx++; return items[idx] || null; },
      next: function () { if (idx > 0) idx--; return items[idx] || null; },
      all: function () { return items.slice(); }
    };
  }

  // ── Smart SQL suggestions ─────────────────────────────────────────────────
  function buildSmartSuggestions(dataset) {
    if (!dataset || !dataset.columns) return [];
    var tbl = '"' + safeTableName(dataset.name) + '"';
    var cols = dataset.columns;
    var numCols = cols.filter(function (c) { return c.type === 'number' || c.type === 'integer' || c.type === 'double'; });
    var catCols = cols.filter(function (c) { return c.type === 'text' || c.type === 'varchar'; });
    var dateCols = cols.filter(function (c) { return c.type === 'date' || c.type === 'timestamp'; });
    var suggestions = [];

    // Row count
    suggestions.push({ label: 'Count all rows', sql: 'SELECT COUNT(*) AS total_rows\nFROM ' + tbl });

    // Null check
    if (cols.length) {
      suggestions.push({
        label: 'Check null counts',
        sql: 'SELECT\n' + cols.slice(0, 6).map(function (c) {
          return '  COUNT(*) - COUNT("' + c.name + '") AS "' + c.name + '_nulls"';
        }).join(',\n') + '\nFROM ' + tbl
      });
    }

    // Group by + avg for first categorical + numeric pair
    if (catCols.length && numCols.length) {
      suggestions.push({
        label: 'Group by ' + catCols[0].name,
        sql: 'SELECT\n  "' + catCols[0].name + '",\n  COUNT(*) AS count,\n  ROUND(AVG("' + numCols[0].name + '"), 2) AS avg_' + numCols[0].name.replace(/[^a-z0-9]/gi, '_') + '\nFROM ' + tbl + '\nGROUP BY "' + catCols[0].name + '"\nORDER BY count DESC\nLIMIT 10'
      });
    }

    // Top N by numeric
    if (numCols.length) {
      suggestions.push({
        label: 'Top 10 by ' + numCols[0].name,
        sql: 'SELECT *\nFROM ' + tbl + '\nORDER BY "' + numCols[0].name + '" DESC\nLIMIT 10'
      });
    }

    // Date trend
    if (dateCols.length && numCols.length) {
      suggestions.push({
        label: 'Monthly trend',
        sql: 'SELECT\n  DATE_TRUNC(\'month\', "' + dateCols[0].name + '") AS month,\n  COUNT(*) AS count,\n  ROUND(SUM("' + numCols[0].name + '"), 2) AS total\nFROM ' + tbl + '\nGROUP BY month\nORDER BY month'
      });
    }

    // Duplicates
    if (cols.length) {
      suggestions.push({
        label: 'Find duplicates',
        sql: 'SELECT\n  ' + cols.slice(0, 3).map(function (c) { return '"' + c.name + '"'; }).join(', ') + ',\n  COUNT(*) AS occurrences\nFROM ' + tbl + '\nGROUP BY ' + cols.slice(0, 3).map(function (c) { return '"' + c.name + '"'; }).join(', ') + '\nHAVING COUNT(*) > 1\nORDER BY occurrences DESC'
      });
    }

    return suggestions;
  }

  // ── Results export ────────────────────────────────────────────────────────
  function exportResultsCSV(columns, rows) {
    var lines = [columns.map(function (c) { return JSON.stringify(c.name); }).join(',')];
    rows.forEach(function (row) {
      lines.push(columns.map(function (c) {
        var v = row[c.name];
        return v === null || v === undefined ? '' : JSON.stringify(String(v));
      }).join(','));
    });
    var blob = new Blob([lines.join('\n')], { type: 'text/csv' });
    var a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = 'query_results.csv';
    a.click();
    setTimeout(function () { URL.revokeObjectURL(a.href); }, 2000);
  }

  // ── Public init ───────────────────────────────────────────────────────────
  function init(opts) {
    // opts: { getDatasets, onResultReady, onError }
    var adapter = createDuckDBAdapter();
    var history = createHistory();
    var lastResult = null;

    return {
      loadDataset: async function (dataset) {
        try { await adapter.registerDataset(dataset); } catch (e) { /* silent */ }
      },
      runQuery: async function (sql, datasets) {
        try {
          var result = await adapter.query(sql, datasets || []);
          lastResult = result;
          if (opts && opts.onResultReady) opts.onResultReady(result, sql);
          return result;
        } catch (e) {
          var msg = translateError(e.message || String(e));
          if (opts && opts.onError) opts.onError(msg, sql);
          throw new Error(msg);
        }
      },
      history: history,
      getLastResult: function () { return lastResult; },
      exportLastResult: function () {
        if (lastResult) exportResultsCSV(lastResult.columns, lastResult.rows);
      },
      buildSmartSuggestions: buildSmartSuggestions,
      buildAutocomplete: buildAutocomplete,
      safeTableName: safeTableName
    };
  }

  return { init: init, SQL_KEYWORDS: SQL_KEYWORDS, safeTableName: safeTableName, exportResultsCSV: exportResultsCSV };
})();
  /* ---- end sql-engine.js ---- */

  /* ---- from js/dashboard/findings-rail.js ---- */
/**
 * findings-rail.js — DataGlow Findings Rail (PR AU)
 *
 * The Findings Rail sits above the KPI cards in the dashboard view.
 * It reads the dataset's validation findings + stats and produces
 * 3-5 ranked, plain-English insight cards, each containing:
 *   - A context-anchored headline (anomaly-first when triggered)
 *   - A "why this matters" sentence
 *   - A root-cause decomposition when an anomaly is present
 *   - A one-line suggested next step
 *   - A provenance tag (which column + which rows)
 *   - A JSON export in a <details> tag for agent consumption
 *
 * Zero external dependencies. All compute is synchronous over data
 * already in browser memory. Nothing is transmitted.
 *
 * Public API:
 *   FindingsRail.render(dataset, containerEl)
 *   FindingsRail.clear(containerEl)
 */

var FindingsRail = (function () {
  'use strict';

  // ── Helpers ───────────────────────────────────────────────────────────────
  function fmt(n) {
    if (n === null || n === undefined || isNaN(n)) return 'N/A';
    var abs = Math.abs(n);
    if (abs >= 1e6) return (n / 1e6).toFixed(1) + 'M';
    if (abs >= 1e3) return (n / 1e3).toFixed(1) + 'K';
    if (n !== Math.floor(n)) return parseFloat(n.toFixed(2)).toLocaleString();
    return n.toLocaleString();
  }
  function pct(n) { return (n >= 0 ? '+' : '') + n.toFixed(1) + '%'; }
  function isNum(v) { return v !== null && v !== undefined && v !== '' && !isNaN(parseFloat(v)) && isFinite(v); }
  function num(v)  { return parseFloat(v); }
  function colIdx(dataset, name) {
    for (var i = 0; i < dataset.columns.length; i++) {
      if (dataset.columns[i].name === name) return i;
    }
    return -1;
  }
  function colVals(dataset, colName) {
    var ci = colIdx(dataset, colName);
    if (ci < 0) return [];
    return dataset.rows.map(function (r) { return r[ci]; });
  }
  function numVals(dataset, colName) {
    return colVals(dataset, colName).filter(isNum).map(num);
  }
  function mean(arr) {
    if (!arr.length) return 0;
    return arr.reduce(function (s, v) { return s + v; }, 0) / arr.length;
  }
  function stddev(arr) {
    if (arr.length < 2) return 0;
    var m = mean(arr);
    return Math.sqrt(arr.reduce(function (s, v) { return s + Math.pow(v - m, 2); }, 0) / arr.length);
  }
  function escHtml(s) {
    return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  }
  function titleCase(s) {
    return s.replace(/_/g, ' ').replace(/\b\w/g, function (c) { return c.toUpperCase(); });
  }

  // ── Finding generators ────────────────────────────────────────────────────

  // 1. Summary card  -  overall data health
  function findingSummary(dataset) {
    var totalRows = dataset.rows.length;
    var totalCols = dataset.columns.length;
    var findings  = dataset.findings || [];
    var errors    = (dataset.rowFlags || []).filter(function (f) { return f && f.error; }).length;
    var warnings  = (dataset.rowFlags || []).filter(function (f) { return f && f.warning; }).length;
    var score     = dataset.score != null ? dataset.score : null;

    var scoreLabel = score !== null
      ? (score >= 90 ? 'Excellent' : score >= 75 ? 'Good' : score >= 60 ? 'Fair' : 'Poor')
      : null;

    var headline, detail, action;
    if (errors === 0 && warnings === 0) {
      headline = totalRows.toLocaleString() + ' rows, ' + totalCols + ' columns, no issues found.';
      detail   = 'Every value passed validation. This dataset is ready for analysis and dashboard delivery.';
      action   = 'You can proceed directly to SQL queries or the Dashboard view.';
    } else if (errors > 0) {
      headline = errors.toLocaleString() + ' row' + (errors === 1 ? '' : 's') + ' with errors detected.';
      detail   = 'Errors prevent reliable aggregation. Fix or exclude these rows before sharing results.';
      action   = 'Open the Validation Rail to see which rows are affected and why.';
    } else {
      headline = warnings.toLocaleString() + ' row' + (warnings === 1 ? '' : 's') + ' flagged for review.';
      detail   = 'Warnings do not block analysis but may skew averages and totals if left in.';
      action   = 'Review flagged rows in the Validation Rail. Consider filtering them before aggregating.';
    }

    return {
      id: 'summary',
      priority: 1,
      icon: errors > 0 ? 'error' : warnings > 0 ? 'warning' : 'ok',
      headline: headline,
      detail: detail,
      action: action,
      provenance: totalRows + ' rows across ' + totalCols + ' columns',
      scoreLabel: scoreLabel,
      score: score,
      json: {
        type: 'summary',
        rows: totalRows,
        columns: totalCols,
        errors: errors,
        warnings: warnings,
        score: score
      }
    };
  }

  // 2. Anomaly finding for each numeric column
  function findingAnomalies(dataset) {
    var results = [];
    dataset.columns.forEach(function (col, ci) {
      if (col.type !== 'INT' && col.type !== 'FLOAT' &&
          col.type !== 'number' && col.type !== 'integer' && col.type !== 'float' && col.type !== 'double') return;

      var vals = dataset.rows.map(function (r) { return r[ci]; }).filter(isNum).map(num);
      if (vals.length < 5) return;

      var m   = mean(vals);
      var sd  = stddev(vals);
      if (sd === 0) return;

      // Find outlier rows
      var outlierRows = [];
      dataset.rows.forEach(function (r, ri) {
        var v = r[ci];
        if (!isNum(v)) return;
        var z = Math.abs((num(v) - m) / sd);
        if (z > 2.5) outlierRows.push({ rowIdx: ri, value: num(v), z: z });
      });

      if (!outlierRows.length) return;

      // Root-cause: which categorical column best explains outliers?
      var catDrivers = [];
      dataset.columns.forEach(function (catCol, cci) {
        if (cci === ci) return;
        if (catCol.type === 'INT' || catCol.type === 'FLOAT' ||
            catCol.type === 'number' || catCol.type === 'float' || catCol.type === 'integer') return;
        var outlierKeys = outlierRows.map(function (o) { return String(dataset.rows[o.rowIdx][cci]); });
        var allKeys     = dataset.rows.map(function (r) { return String(r[cci]); });
        // Check if outliers concentrate in one group
        var freq = {};
        outlierKeys.forEach(function (k) { freq[k] = (freq[k] || 0) + 1; });
        var topKey = Object.keys(freq).sort(function (a, b) { return freq[b] - freq[a]; })[0];
        if (!topKey) return;
        var topCount   = freq[topKey];
        var totalInGrp = allKeys.filter(function (k) { return k === topKey; }).length;
        if (topCount / outlierRows.length >= 0.5 && totalInGrp > 0) {
          catDrivers.push({ colName: catCol.name, groupName: topKey, count: topCount, groupTotal: totalInGrp });
        }
      });

      var topDriver = catDrivers.length ? catDrivers[0] : null;
      var direction = outlierRows[0].value > m ? 'above' : 'below';
      var extreme   = outlierRows.reduce(function (a, b) { return b.z > a.z ? b : a; });

      var headline = titleCase(col.name) + ': ' + outlierRows.length + ' outlier' +
        (outlierRows.length === 1 ? '' : 's') + ' detected (' + direction + ' average).';
      var detail = 'Average ' + titleCase(col.name) + ' is ' + fmt(m) +
        '. The extreme value is ' + fmt(extreme.value) + ' (' + extreme.z.toFixed(1) + '\u03c3 from mean).';
      var action = topDriver
        ? 'Investigate rows where ' + titleCase(topDriver.colName) + ' = "' + topDriver.groupName +
          '" (' + topDriver.count + ' of ' + outlierRows.length + ' outliers cluster there).'
        : 'Filter for rows with ' + titleCase(col.name) + ' outside ' + fmt(m - 2*sd) +
          ' to ' + fmt(m + 2*sd) + ' and validate manually.';

      results.push({
        id: 'anomaly-' + col.name,
        priority: 2,
        icon: 'anomaly',
        headline: headline,
        detail: detail,
        action: action,
        provenance: col.name + '  -  ' + vals.length + ' values, ' + outlierRows.length + ' outliers',
        rootCause: topDriver ? (titleCase(topDriver.colName) + ' = "' + topDriver.groupName + '"') : null,
        json: {
          type: 'anomaly',
          column: col.name,
          mean: parseFloat(m.toFixed(4)),
          stddev: parseFloat(sd.toFixed(4)),
          outlierCount: outlierRows.length,
          extremeValue: extreme.value,
          driver: topDriver
        }
      });
    });
    return results;
  }

  // 3. Missing data finding
  function findingMissing(dataset) {
    var results = [];
    dataset.columns.forEach(function (col, ci) {
      var nullCount = dataset.rows.filter(function (r) {
        var v = r[ci];
        return v === null || v === undefined || v === '';
      }).length;
      var pctMiss = nullCount / dataset.rows.length;
      if (pctMiss < 0.05) return; // ignore < 5%

      var headline = titleCase(col.name) + ': ' + nullCount.toLocaleString() +
        ' missing values (' + (pctMiss * 100).toFixed(0) + '% of rows).';
      var detail = pctMiss >= 0.3
        ? 'Over 30% of ' + titleCase(col.name) + ' is blank. This column may be unreliable for aggregations.'
        : 'Scattered nulls in ' + titleCase(col.name) + ' will produce understated counts and averages.';
      var action = pctMiss >= 0.5
        ? 'Consider dropping this column or imputing with a default value before analysis.'
        : 'Filter out nulls with WHERE "' + col.name + '" IS NOT NULL before aggregating.';

      results.push({
        id: 'missing-' + col.name,
        priority: 3,
        icon: 'warning',
        headline: headline,
        detail: detail,
        action: action,
        provenance: col.name + '  -  ' + nullCount + '/' + dataset.rows.length + ' rows null',
        json: {
          type: 'missing',
          column: col.name,
          nullCount: nullCount,
          totalRows: dataset.rows.length,
          pctMissing: parseFloat((pctMiss * 100).toFixed(1))
        }
      });
    });
    return results.slice(0, 2); // max 2 missing findings
  }

  // 4. Context-anchored KPI finding (trailing comparison)
  function findingKPIContext(dataset) {
    var results = [];
    var numCols = dataset.columns.filter(function (col, ci) {
      var vals = dataset.rows.map(function (r) { return r[ci]; }).filter(isNum);
      return vals.length >= dataset.rows.length * 0.6;
    });
    if (numCols.length === 0) return results;

    // Split into first half vs second half
    var mid = Math.floor(dataset.rows.length / 2);
    var firstHalf  = dataset.rows.slice(0, mid);
    var secondHalf = dataset.rows.slice(mid);

    numCols.slice(0, 2).forEach(function (col) {
      var ci = dataset.columns.indexOf(col);
      var v1 = mean(firstHalf.map(function (r) { return r[ci]; }).filter(isNum).map(num));
      var v2 = mean(secondHalf.map(function (r) { return r[ci]; }).filter(isNum).map(num));
      if (!v1 || !v2 || v1 === 0) return;
      var delta = ((v2 - v1) / Math.abs(v1)) * 100;
      if (Math.abs(delta) < 3) return; // ignore tiny changes

      var dir = delta > 0 ? 'increased' : 'decreased';
      var headline = titleCase(col.name) + ' ' + dir + ' ' + Math.abs(delta).toFixed(1) +
        '% from first half to second half of the dataset.';
      var detail = 'First-half average: ' + fmt(v1) + '. Second-half average: ' + fmt(v2) + '.';
      var action = 'Sort by a date column and re-run for a time-series trend. This comparison is row-order based.';

      results.push({
        id: 'kpi-trend-' + col.name,
        priority: 4,
        icon: delta > 0 ? 'up' : 'down',
        headline: headline,
        detail: detail,
        action: action,
        provenance: col.name + '  -  rows 1-' + mid + ' vs ' + (mid+1) + '-' + dataset.rows.length,
        json: {
          type: 'kpi_trend',
          column: col.name,
          firstHalfMean: parseFloat(v1.toFixed(4)),
          secondHalfMean: parseFloat(v2.toFixed(4)),
          deltaPercent: parseFloat(delta.toFixed(2))
        }
      });
    });
    return results;
  }

  // ── Render a single finding card ─────────────────────────────────────────
  function iconSVG(type) {
    var icons = {
      ok:      '<svg width="16" height="16" viewBox="0 0 16 16" fill="none"><circle cx="8" cy="8" r="7" stroke="#16A34A" stroke-width="1.5"/><path d="M5 8l2 2 4-4" stroke="#16A34A" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>',
      warning: '<svg width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M8 2L14.5 13.5H1.5L8 2Z" stroke="#D97706" stroke-width="1.5" stroke-linejoin="round"/><line x1="8" y1="6.5" x2="8" y2="9.5" stroke="#D97706" stroke-width="1.5" stroke-linecap="round"/><circle cx="8" cy="11.5" r="0.75" fill="#D97706"/></svg>',
      error:   '<svg width="16" height="16" viewBox="0 0 16 16" fill="none"><circle cx="8" cy="8" r="7" stroke="#DC2626" stroke-width="1.5"/><line x1="5.5" y1="5.5" x2="10.5" y2="10.5" stroke="#DC2626" stroke-width="1.5" stroke-linecap="round"/><line x1="10.5" y1="5.5" x2="5.5" y2="10.5" stroke="#DC2626" stroke-width="1.5" stroke-linecap="round"/></svg>',
      anomaly: '<svg width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M2 10l3-5 3 3 2-4 4 6" stroke="#4F98A3" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>',
      up:      '<svg width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M8 12V4M4 8l4-4 4 4" stroke="#16A34A" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>',
      down:    '<svg width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M8 4v8M4 8l4 4 4-4" stroke="#DC2626" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>',
    };
    return icons[type] || icons.ok;
  }

  function renderCard(finding) {
    var card = document.createElement('div');
    card.className = 'fr-card fr-card-' + finding.icon;

    var jsonStr = JSON.stringify(finding.json, null, 2);

    card.innerHTML =
      '<div class="fr-card-header">' +
        '<span class="fr-icon">' + iconSVG(finding.icon) + '</span>' +
        '<span class="fr-headline">' + escHtml(finding.headline) + '</span>' +
      '</div>' +
      '<p class="fr-detail">' + escHtml(finding.detail) + '</p>' +
      (finding.rootCause
        ? '<div class="fr-root-cause"><span class="fr-rc-label">Driver:</span> ' + escHtml(finding.rootCause) + '</div>'
        : '') +
      '<div class="fr-action"><span class="fr-action-label">Next step:</span> ' + escHtml(finding.action) + '</div>' +
      '<details class="fr-json-block">' +
        '<summary class="fr-json-toggle">View details</summary>' +
        '<pre class="fr-json-pre">' + escHtml(jsonStr) + '</pre>' +
      '</details>' +
      '<div class="fr-provenance">' + escHtml(finding.provenance) + '</div>';

    return card;
  }

  // ── Main render ───────────────────────────────────────────────────────────
  function render(dataset, containerEl) {
    if (!containerEl) return;
    containerEl.innerHTML = '';

    if (!dataset || !dataset.rows || !dataset.rows.length) {
      containerEl.innerHTML = '<div class="fr-empty">Drop a dataset to see findings.</div>';
      return;
    }

    // Collect all findings
    var all = [];
    all.push(findingSummary(dataset));
    findingAnomalies(dataset).forEach(function (f) { all.push(f); });
    findingMissing(dataset).forEach(function (f) { all.push(f); });
    findingKPIContext(dataset).forEach(function (f) { all.push(f); });

    // Sort by priority, cap at 5
    all.sort(function (a, b) { return a.priority - b.priority; });
    var shown = all.slice(0, 5);

    // Rail header
    var header = document.createElement('div');
    header.className = 'fr-header';
    header.innerHTML =
      '<span class="fr-header-title">Findings</span>' +
      '<span class="fr-header-count">' + shown.length + ' insight' + (shown.length === 1 ? '' : 's') + '</span>';
    containerEl.appendChild(header);

    // Cards
    var list = document.createElement('div');
    list.className = 'fr-list';
    shown.forEach(function (f) { list.appendChild(renderCard(f)); });
    containerEl.appendChild(list);

    // "No anomalies" footer when clean
    if (shown.length === 1 && shown[0].id === 'summary' && shown[0].icon === 'ok') {
      var footer = document.createElement('div');
      footer.className = 'fr-clean-footer';
      footer.textContent = 'No anomalies or data quality issues detected. Proceed with confidence.';
      containerEl.appendChild(footer);
    }
  }

  function clear(containerEl) {
    if (containerEl) containerEl.innerHTML = '';
  }

  return { render: render, clear: clear };
})();

  /* ---- end findings-rail.js ---- */

/* ---- from js/dashboard/proof-chain-rail.js ---- */
/* DataGlow -- js/dashboard/proof-chain-rail.js */
/* PR AZ: Proof Chain Rail -- SQL + Python lineage visible on every AI insight */

/**
 * ProofChainRail -- wraps every insight card with its verifiable SQL and Python lineage.
 *
 * Philosophy: "DataGlow shows its work."
 * Every claim made by the insight engine must be traceable to:
 *   1. The SQL that produced the number (DuckDB-verifiable)
 *   2. The equivalent Python/pandas code that reproduces the same result
 *   3. The columns and row-range it touched
 *   4. A confidence tier (Verified / Estimated / Inferred)
 *
 * Public API:
 *   ProofChainRail.attachToCard(cardEl, proof)
 *   ProofChainRail.buildProof(findingObj, dataset) -> proofObj
 *   ProofChainRail.renderInline(containerEl, dataset, findings)
 *   ProofChainRail.attachToChartCard(cardEl, colName, chartType, dataset)
 */

var ProofChainRail = (function () {
  'use strict';

  /* ---- confidence tier classification ---- */
  function confidenceTier(finding) {
    var c = finding.confidence;
    if (c === undefined || c === null) c = 0.7;
    if (c >= 0.9) return { label: 'Verified', cls: 'pcr-tier-verified', icon: '\u2713' };
    if (c >= 0.7) return { label: 'Estimated', cls: 'pcr-tier-estimated', icon: '\u223C' };
    return { label: 'Inferred', cls: 'pcr-tier-inferred', icon: '\u2248' };
  }

  /* ---- build the SQL that explains the finding ---- */
  function buildExplanatorySQL(finding, dataset) {
    if (!dataset || !dataset.columns || !dataset.rows) return null;
    var tbl = '"' + (dataset.name || 'dataset').replace(/"/g, '') + '"';
    var type = finding.type || finding.statType || 'summary';
    var col = finding.col || finding.column || null;
    var colB = finding.colB || null;

    if (col && (type === 'outlier' || type === 'anomaly')) {
      var mean = (finding.mean || 0).toFixed(2);
      var sd3  = ((finding.stddev || 0) * 3).toFixed(2);
      return [
        'SELECT "' + col + '",',
        '       COUNT(*) AS row_count,',
        '       AVG("' + col + '") AS avg_val,',
        '       STDDEV("' + col + '") AS stddev_val',
        'FROM ' + tbl,
        'WHERE ABS("' + col + '" - ' + mean + ') > ' + sd3,
        'ORDER BY ABS("' + col + '" - ' + mean + ') DESC',
        'LIMIT 20'
      ].join('\n');
    }

    if (col && (type === 'correlation' || type === 'skew')) {
      var col2 = colB || col;
      return [
        'SELECT',
        '  CORR("' + col + '", "' + col2 + '") AS correlation,',
        '  AVG("' + col + '")              AS avg_' + safeAlias(col) + ',',
        '  AVG("' + col2 + '")             AS avg_' + safeAlias(col2),
        'FROM ' + tbl
      ].join('\n');
    }

    if (col && (type === 'top_category' || type === 'categorical')) {
      return [
        'SELECT "' + col + '",',
        '       COUNT(*) AS freq,',
        '       ROUND(COUNT(*) * 100.0 / SUM(COUNT(*)) OVER (), 1) AS pct',
        'FROM ' + tbl,
        'GROUP BY "' + col + '"',
        'ORDER BY freq DESC',
        'LIMIT 10'
      ].join('\n');
    }

    if (col && (type === 'numeric' || type === 'distribution')) {
      return [
        'SELECT',
        '  COUNT("' + col + '")         AS n,',
        '  AVG("' + col + '")           AS mean,',
        '  MEDIAN("' + col + '")        AS median,',
        '  STDDEV("' + col + '")        AS stddev,',
        '  MIN("' + col + '")           AS min,',
        '  MAX("' + col + '")           AS max,',
        '  PERCENTILE_CONT(0.25) WITHIN GROUP (ORDER BY "' + col + '") AS p25,',
        '  PERCENTILE_CONT(0.75) WITHIN GROUP (ORDER BY "' + col + '") AS p75',
        'FROM ' + tbl
      ].join('\n');
    }

    if (col && (type === 'null_rate' || type === 'missing')) {
      return [
        'SELECT',
        '  COUNT(*) AS total_rows,',
        '  COUNT("' + col + '") AS non_null,',
        '  COUNT(*) - COUNT("' + col + '") AS null_count,',
        '  ROUND((COUNT(*) - COUNT("' + col + '")) * 100.0 / COUNT(*), 1) AS null_pct',
        'FROM ' + tbl
      ].join('\n');
    }

    /* generic fallback */
    var colList = dataset.columns.slice(0, 6).map(function (c) {
      return '  AVG(TRY_CAST("' + c.name + '" AS DOUBLE)) AS avg_' + safeAlias(c.name);
    }).join(',\n');
    return [
      'SELECT',
      '  COUNT(*) AS total_rows,',
      colList,
      'FROM ' + tbl
    ].join('\n');
  }

  /* ---- build the Python/pandas code that reproduces the finding ---- */
  function buildExplanatoryPython(finding, dataset) {
    if (!dataset || !dataset.columns || !dataset.rows) return null;
    var dfName = 'df';
    var dsName = (dataset.name || 'dataset').replace(/[^a-zA-Z0-9_]/g, '_');
    var type = finding.type || finding.statType || 'summary';
    var col = finding.col || finding.column || null;
    var colB = finding.colB || null;

    /* header comment -- always shown */
    var header = [
      '# DataGlow Python lineage -- reproduces this insight with pandas',
      '# Load your data:',
      '# df = pd.read_csv("' + dsName + '.csv")',
      '# or: df = dataglow.get_df("' + dsName + '")',
      ''
    ].join('\n');

    if (col && (type === 'outlier' || type === 'anomaly')) {
      var mean = (finding.mean || 0).toFixed(4);
      var stddev = (finding.stddev || 0).toFixed(4);
      return header + [
        'import pandas as pd',
        '',
        'mean_val  = ' + mean,
        'stddev_val = ' + stddev,
        'threshold = stddev_val * 3',
        '',
        'outliers = df[abs(df["' + col + '"] - mean_val) > threshold].copy()',
        'outliers = outliers.sort_values(',
        '    by="' + col + '",',
        '    key=lambda s: (s - mean_val).abs(),',
        '    ascending=False',
        ').head(20)',
        '',
        'print(f"Outliers in \'' + col + '\': {len(outliers)} / {len(df)} rows")',
        'print(outliers[["' + col + '"]].describe())'
      ].join('\n');
    }

    if (col && (type === 'correlation' || type === 'skew')) {
      var col2 = colB || col;
      if (col === col2) {
        return header + [
          'import pandas as pd',
          '',
          '# Skewness of ' + col,
          'skew = df["' + col + '"].skew()',
          'print(f"Skewness of \'' + col + '\': {skew:.4f}")',
          '',
          '# Distribution stats',
          'print(df["' + col + '"].describe())'
        ].join('\n');
      }
      return header + [
        'import pandas as pd',
        '',
        '# Pearson correlation',
        'corr = df["' + col + '"].corr(df["' + col2 + '"])',
        'print(f"Correlation \'' + col + '\' vs \'' + col2 + '\': {corr:.4f}")',
        '',
        '# Pair stats',
        'print(df[["' + col + '", "' + col2 + '"]].describe())'
      ].join('\n');
    }

    if (col && (type === 'top_category' || type === 'categorical')) {
      return header + [
        'import pandas as pd',
        '',
        'freq = (',
        '    df["' + col + '"].value_counts()',
        '    .reset_index()',
        '    .rename(columns={"' + col + '": "freq", "index": "' + col + '"})',
        '    .head(10)',
        ')',
        'freq["pct"] = (freq["freq"] / len(df) * 100).round(1)',
        'print(freq)'
      ].join('\n');
    }

    if (col && (type === 'numeric' || type === 'distribution')) {
      return header + [
        'import pandas as pd',
        '',
        'stats = df["' + col + '"].describe(percentiles=[0.25, 0.5, 0.75])',
        'stats["median"] = df["' + col + '"].median()',
        'stats["stddev"] = df["' + col + '"].std()',
        'print(stats)'
      ].join('\n');
    }

    if (col && (type === 'null_rate' || type === 'missing')) {
      return header + [
        'import pandas as pd',
        '',
        'total    = len(df)',
        'non_null = df["' + col + '"].count()',
        'null_ct  = total - non_null',
        'null_pct = round(null_ct / total * 100, 1)',
        '',
        'print(f"Column: \'' + col + '\'")',
        'print(f"  Total rows : {total:,}")',
        'print(f"  Non-null   : {non_null:,}")',
        'print(f"  Null count : {null_ct:,} ({null_pct}%)")'
      ].join('\n');
    }

    /* generic summary fallback */
    var numCols = dataset.columns
      .filter(function (c) { return c.type === 'INT' || c.type === 'FLOAT'; })
      .slice(0, 6)
      .map(function (c) { return '"' + c.name + '"'; });
    var colStr = numCols.length ? '[' + numCols.join(', ') + ']' : 'df.select_dtypes(include="number").columns.tolist()';
    return header + [
      'import pandas as pd',
      '',
      '# Dataset summary',
      'print(f"Rows: {len(df):,}  Cols: {len(df.columns)}")',
      'print()',
      'print(df[' + colStr + '].describe())'
    ].join('\n');
  }

  function safeAlias(name) {
    return (name || 'col').replace(/[^a-zA-Z0-9]/g, '_').toLowerCase().slice(0, 20);
  }

  /* ---- build a proof object for a finding ---- */
  function buildProof(finding, dataset) {
    if (!finding || !dataset) return null;
    var tier = confidenceTier(finding);
    var sql  = buildExplanatorySQL(finding, dataset);
    var python = buildExplanatoryPython(finding, dataset);
    var rowsAffected = finding.rowsAffected || finding.outlierCount || null;
    var colsInvolved = [];
    if (finding.col)  colsInvolved.push(finding.col);
    if (finding.colB) colsInvolved.push(finding.colB);
    if (finding.column) colsInvolved.push(finding.column);

    return {
      tier: tier,
      sql: sql,
      python: python,
      rowsAffected: rowsAffected,
      totalRows: dataset.rows ? dataset.rows.length : 0,
      colsInvolved: colsInvolved,
      computedAt: new Date().toISOString(),
      engine: 'DataGlow InstantInsight v1',
      datasetName: dataset.name || 'dataset',
      hash: djb2(JSON.stringify({ finding: finding.type, col: finding.col, ds: dataset.name }))
    };
  }

  function djb2(str) {
    var h = 5381;
    for (var i = 0; i < str.length; i++) h = ((h * 33) ^ str.charCodeAt(i)) >>> 0;
    return h.toString(16).slice(0, 8);
  }

  /* ---- attach proof footer to an existing insight card element ---- */
  function attachToCard(cardEl, proof) {
    if (!cardEl || !proof) return;
    /* remove existing */
    var old = cardEl.querySelector('.pcr-footer');
    if (old) old.parentNode.removeChild(old);

    var footer = document.createElement('div');
    footer.className = 'pcr-footer';

    /* tier badge */
    var tierBadge = document.createElement('span');
    tierBadge.className = 'pcr-tier ' + proof.tier.cls;
    tierBadge.textContent = proof.tier.icon + ' ' + proof.tier.label;
    footer.appendChild(tierBadge);

    /* row scope */
    if (proof.rowsAffected !== null && proof.rowsAffected !== undefined) {
      var scope = document.createElement('span');
      scope.className = 'pcr-scope';
      scope.textContent = proof.rowsAffected.toLocaleString() + ' / ' + proof.totalRows.toLocaleString() + ' rows';
      footer.appendChild(scope);
    }

    /* columns touched */
    if (proof.colsInvolved && proof.colsInvolved.length) {
      var cols = document.createElement('span');
      cols.className = 'pcr-cols';
      cols.textContent = proof.colsInvolved.slice(0, 3).join(', ');
      footer.appendChild(cols);
    }

    /* expand SQL button */
    if (proof.sql) {
      var sqlBtn = document.createElement('button');
      sqlBtn.className = 'pcr-sql-btn';
      sqlBtn.title = 'View the SQL behind this insight';
      sqlBtn.innerHTML = '<span class="pcr-sql-icon">\u007B\u007D</span> SQL';
      sqlBtn.setAttribute('data-sql', proof.sql);
      sqlBtn.setAttribute('data-hash', proof.hash || '');
      sqlBtn.addEventListener('click', function (e) {
        e.stopPropagation();
        toggleCodeDrawer(cardEl, proof.sql, proof.hash, 'sql');
      });
      footer.appendChild(sqlBtn);
    }

    /* expand Python button */
    if (proof.python) {
      var pyBtn = document.createElement('button');
      pyBtn.className = 'pcr-py-btn';
      pyBtn.title = 'View the Python code that reproduces this insight';
      pyBtn.innerHTML = '\u03BB Python';
      pyBtn.setAttribute('data-python', proof.python);
      pyBtn.addEventListener('click', function (e) {
        e.stopPropagation();
        toggleCodeDrawer(cardEl, proof.python, proof.hash, 'python');
      });
      footer.appendChild(pyBtn);
    }

    /* copy proof hash */
    var hashEl = document.createElement('span');
    hashEl.className = 'pcr-hash';
    hashEl.title = 'Proof fingerprint: ' + proof.hash;
    hashEl.textContent = '#' + (proof.hash || '').slice(0, 7);
    hashEl.style.cursor = 'pointer';
    hashEl.addEventListener('click', function () {
      try { navigator.clipboard.writeText(proof.hash); } catch (_) {}
      hashEl.textContent = 'Copied!';
      setTimeout(function () { hashEl.textContent = '#' + (proof.hash || '').slice(0, 7); }, 1500);
    });
    footer.appendChild(hashEl);

    cardEl.appendChild(footer);
  }

  /* ---- unified code drawer (SQL or Python) ---- */
  function toggleCodeDrawer(cardEl, code, hash, lang) {
    var existing = cardEl.querySelector('.pcr-sql-drawer');
    /* if same lang drawer is open, toggle it; if different lang, replace it */
    if (existing) {
      var existingLang = existing.getAttribute('data-lang');
      if (existingLang === lang) {
        existing.classList.toggle('pcr-drawer-open');
        return;
      }
      /* different lang: remove and rebuild below */
      existing.parentNode.removeChild(existing);
    }
    buildCodeDrawer(cardEl, code, hash, lang);
  }

  function buildCodeDrawer(cardEl, code, hash, lang) {
    var drawer = document.createElement('div');
    drawer.className = 'pcr-sql-drawer pcr-drawer-open';
    drawer.setAttribute('data-lang', lang);

    var header = document.createElement('div');
    header.className = 'pcr-drawer-header';

    var label = document.createElement('span');
    label.className = 'pcr-drawer-label';
    if (lang === 'python') {
      label.innerHTML = '<span style="color:var(--primary)">\u03BB Python lineage</span> -- copy to Python tab to reproduce';
    } else {
      label.innerHTML = '<span style="color:var(--proof)">Verify this insight</span> -- run this SQL in the editor';
    }
    header.appendChild(label);

    var actions = document.createElement('div');
    actions.className = 'pcr-drawer-actions';

    if (lang === 'sql') {
      var runBtn = document.createElement('button');
      runBtn.className = 'pcr-drawer-run';
      runBtn.textContent = 'Run in SQL Editor';
      runBtn.addEventListener('click', function () { pushSQLToEditor(code); });
      actions.appendChild(runBtn);
    } else {
      var pyBtn = document.createElement('button');
      pyBtn.className = 'pcr-drawer-run';
      pyBtn.textContent = 'Open Python Tab';
      pyBtn.addEventListener('click', function () { pushPythonToEditor(code); });
      actions.appendChild(pyBtn);
    }

    var copyBtn = document.createElement('button');
    copyBtn.className = 'pcr-drawer-copy';
    copyBtn.textContent = 'Copy';
    copyBtn.addEventListener('click', function () {
      try { navigator.clipboard.writeText(code); } catch (_) {}
      copyBtn.textContent = 'Copied!';
      setTimeout(function () { copyBtn.textContent = 'Copy'; }, 1500);
    });

    var closeBtn = document.createElement('button');
    closeBtn.className = 'pcr-drawer-close';
    closeBtn.textContent = '\u00D7';
    closeBtn.addEventListener('click', function () {
      drawer.classList.remove('pcr-drawer-open');
      setTimeout(function () {
        if (!drawer.classList.contains('pcr-drawer-open') && drawer.parentNode) {
          drawer.parentNode.removeChild(drawer);
        }
      }, 300);
    });

    actions.appendChild(copyBtn);
    actions.appendChild(closeBtn);
    header.appendChild(actions);
    drawer.appendChild(header);

    var pre = document.createElement('pre');
    pre.className = 'pcr-sql-pre';
    pre.textContent = code;
    drawer.appendChild(pre);

    if (hash && lang === 'sql') {
      var hashLine = document.createElement('div');
      hashLine.className = 'pcr-drawer-hash';
      hashLine.textContent = 'Proof fingerprint: ' + hash;
      drawer.appendChild(hashLine);
    }

    cardEl.appendChild(drawer);
  }

  /* ---- push SQL into the SQL editor tab ---- */
  function pushSQLToEditor(sql) {
    var editors = [
      document.getElementById('sql-editor'),
      document.getElementById('sql-input'),
      document.getElementById('sql-view-editor'),
      document.querySelector('#sql-view textarea'),
      document.querySelector('.sql-editor-textarea'),
      document.querySelector('textarea[id*="sql"]')
    ];
    var found = editors.find(function (el) { return el && el.tagName === 'TEXTAREA'; });
    if (found) {
      found.value = sql;
      found.dispatchEvent(new Event('input', { bubbles: true }));
    }
    var sqlNavBtn = document.querySelector('[data-panel="sql-view"]') ||
                    document.querySelector('.sidebar-nav-item[data-panel="sql-view"]') ||
                    document.querySelector('.analyze-pill[data-panel="sql-view"]');
    if (sqlNavBtn) sqlNavBtn.click();
    var analyzeNavBtn = document.querySelector('.nav-btn[data-view="analyze"]');
    if (analyzeNavBtn && !analyzeNavBtn.classList.contains('active')) analyzeNavBtn.click();
  }

  /* ---- push Python code into the Python tab editor ---- */
  function pushPythonToEditor(code) {
    var editors = [
      document.getElementById('py-view-input'),
      document.getElementById('py-editor'),
      document.getElementById('python-editor'),
      document.querySelector('#python-view textarea'),
      document.querySelector('.py-editor textarea')
    ];
    var found = editors.find(function (el) { return el && el.tagName === 'TEXTAREA'; });
    if (found) {
      found.value = code;
      found.dispatchEvent(new Event('input', { bubbles: true }));
    }
    /* switch to Python tab */
    var pyNavBtn = document.querySelector('[data-panel="python-view"]') ||
                   document.querySelector('.sidebar-nav-item[data-panel="python-view"]');
    if (pyNavBtn) pyNavBtn.click();
    var analyzeNavBtn = document.querySelector('.nav-btn[data-view="analyze"]');
    if (analyzeNavBtn && !analyzeNavBtn.classList.contains('active')) analyzeNavBtn.click();
  }

  /* ---- render the proof chain rail above/inside findings rail ---- */
  function renderInline(containerEl, dataset, findings) {
    if (!containerEl || !dataset || !Array.isArray(findings) || !findings.length) return;
    var cards = containerEl.querySelectorAll('.finding-card, .fr-card, .insight-card');
    cards.forEach(function (card, i) {
      var f = findings[i];
      if (!f) return;
      var proof = buildProof(f, dataset);
      if (proof) attachToCard(card, proof);
    });
  }

  /* ---- wrap the chart-engine card with proof ---- */
  function attachToChartCard(cardEl, colName, chartType, dataset) {
    if (!cardEl || !dataset) return;
    var pseudoFinding = {
      type: chartType === 'bar' ? 'categorical' :
            chartType === 'line' ? 'correlation' :
            chartType === 'histogram' ? 'distribution' :
            chartType === 'donut' ? 'top_category' : 'numeric',
      col: colName,
      confidence: 0.92
    };
    var proof = buildProof(pseudoFinding, dataset);
    if (proof) attachToCard(cardEl, proof);
  }

  return {
    buildProof: buildProof,
    attachToCard: attachToCard,
    attachToChartCard: attachToChartCard,
    renderInline: renderInline
  };

}());

/* ---- end proof-chain-rail.js ---- */

  /* ---- from js/dashboard/dashboard-engine.js ---- */
/**
 * dashboard-engine.js — DataGlow Dashboard View (PR AN)
 *
 * DataGlow rows are arrays (not objects). Columns are { name, type } where
 * type is one of: 'INT', 'FLOAT', 'STR', 'DATE', 'BOOL' (from detectType).
 * Access: r[colIdx] — NOT r[col.name].
 *
 * Research-grounded rules:
 *  - Data readiness gate first (null rates, dupes, row count, type consistency)
 *  - 3-4 KPI cards, top row, Z-pattern
 *  - Three-in-one KPI anatomy: headline + sparkline + delta badge
 *  - RAG colors: green #16A34A / amber #D97706 / red #DC2626 — never inverted
 *  - Bar + line charts only — no pie, no 3D, no dual-axis
 *  - 6 charts max
 *  - Outliers flagged, never silently removed
 *  - Export CSV front and center
 */

var DashboardEngine = (function () {
  'use strict';

  var RAG = {
    green: { bg: '#DCFCE7', text: '#15803D', dot: '#16A34A' },
    amber: { bg: '#FEF3C7', text: '#B45309', dot: '#D97706' },
    red:   { bg: '#FEE2E2', text: '#B91C1C', dot: '#DC2626' },
    gray:  { bg: '#F3F4F6', text: '#4B5563', dot: '#6B7280' },
    blue:  { bg: '#DBEAFE', text: '#1D4ED8', dot: '#2563EB' }
  };

  // DataGlow numeric types
  var NUMERIC_TYPES = { 'INT': true, 'FLOAT': true, 'number': true, 'integer': true, 'float': true, 'double': true };
  var TEXT_TYPES    = { 'STR': true, 'BOOL': true, 'text': true, 'varchar': true, 'string': true };
  var DATE_TYPES    = { 'DATE': true, 'date': true, 'timestamp': true };

  function isNum(v) { return v !== null && v !== undefined && v !== '' && !isNaN(parseFloat(v)) && isFinite(v); }
  function toNum(v) { return parseFloat(v); }
  function escH(s)  { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

  function fmtNum(n) {
    if (n === null || n === undefined || isNaN(n)) return '\u2014';
    var abs = Math.abs(n);
    if (abs >= 1e9) return (n/1e9).toFixed(1)+'B';
    if (abs >= 1e6) return (n/1e6).toFixed(1)+'M';
    if (abs >= 1e3) return (n/1e3).toFixed(1)+'K';
    if (abs < 1 && abs > 0) return n.toFixed(2);
    return parseFloat(n.toFixed(2)).toLocaleString();
  }
  function fmtPct(n) {
    if (n === null || isNaN(n)) return '';
    return (n >= 0 ? '+' : '') + (n * 100).toFixed(1) + '%';
  }

  // Get value from a row by column index
  function getVal(row, colIdx) { return row[colIdx]; }

  // ── Data Readiness Check ──────────────────────────────────────────────────
  function runReadinessCheck(dataset) {
    var issues = [], warnings = [], passed = [];
    if (!dataset || !dataset.rows || !dataset.columns) {
      return { pass: false, issues: [{ msg: 'No dataset loaded.', severity: 'block' }], warnings: [], passed: [], outlierCols: [] };
    }
    var rows = dataset.rows, cols = dataset.columns, n = rows.length;

    // Row count
    if (n === 0) {
      issues.push({ severity: 'block', msg: 'Dataset is empty (0 rows).' });
    } else if (n < 30) {
      warnings.push({ severity: 'warn', msg: n + ' rows \u2014 below the 30-row minimum. KPI values may be statistically unreliable.' });
    } else {
      passed.push('Row count: ' + n.toLocaleString() + ' rows');
    }

    // Duplicates (Uber SLA: <=1%)
    var seen = {}, dupeCount = 0;
    rows.forEach(function(r) { var k=JSON.stringify(r); if(seen[k]) dupeCount++; else seen[k]=true; });
    var dupePct = n > 0 ? dupeCount/n : 0;
    if (dupePct > 0.01) {
      issues.push({ severity: 'block', msg: dupeCount + ' duplicate rows (' + (dupePct*100).toFixed(1) + '%) exceeds the 1% threshold.', detail: 'Duplicates inflate KPIs. Use the Grid view to remove them first.' });
    } else if (dupeCount > 0) {
      warnings.push({ severity: 'warn', msg: dupeCount + ' duplicate row(s) found (within 1% tolerance).' });
    } else {
      passed.push('Duplicates: none found');
    }

    // Null rates per numeric column (block >30%, warn 10-30%)
    var highNullCols = [];
    cols.forEach(function(col, ci) {
      var nullC = rows.filter(function(r){ var v=getVal(r,ci); return v===null||v===undefined||v===''; }).length;
      var pct = n > 0 ? nullC/n : 0;
      if (pct > 0.30 && NUMERIC_TYPES[col.type]) {
        highNullCols.push(col.name);
        issues.push({ severity: 'block', field: col.name, msg: '"'+col.name+'": '+(pct*100).toFixed(0)+'% empty \u2014 too incomplete to chart reliably.', detail: 'Above 30% nulls on a metric column produces misleading charts. Fix with Column Editor.' });
      } else if (pct > 0.10) {
        warnings.push({ severity: 'warn', msg: '"'+col.name+'": '+(pct*100).toFixed(0)+'% empty (10\u201330% \u2014 null rows excluded from charts).' });
      }
    });
    if (!highNullCols.length) passed.push('Null rates: all columns within safe thresholds');

    // Outliers (1.5x IQR, flag only, never remove)
    var outlierCols = [];
    cols.forEach(function(col, ci) {
      if (!NUMERIC_TYPES[col.type]) return;
      var vals = rows.map(function(r){return getVal(r,ci);}).filter(isNum).map(toNum);
      if (vals.length < 10) return;
      var sorted = vals.slice().sort(function(a,b){return a-b;});
      var q1=sorted[Math.floor(sorted.length*0.25)], q3=sorted[Math.floor(sorted.length*0.75)];
      var iqr=q3-q1, lo=q1-1.5*iqr, hi=q3+1.5*iqr;
      var cnt=vals.filter(function(v){return v<lo||v>hi;}).length;
      if (cnt > 0) outlierCols.push({ name: col.name, count: cnt });
    });
    if (outlierCols.length) {
      warnings.push({ severity: 'info', msg: 'Outliers flagged in: '+outlierCols.map(function(c){return c.name+' ('+c.count+')';}).join(', ')+'. Shown in context, not removed (Tableau best practice).' });
    }

    return { pass: issues.length===0, issues: issues, warnings: warnings, passed: passed, outlierCols: outlierCols };
  }

  // ── KPI derivation ────────────────────────────────────────────────────────
  function deriveKPIs(dataset) {
    var rows = dataset.rows, cols = dataset.columns;
    // Find numeric columns by type OR by value inspection
    var numColIdxs = [];
    cols.forEach(function(col, ci) {
      if (NUMERIC_TYPES[col.type]) {
        numColIdxs.push(ci);
      } else {
        // Fallback: check if 50%+ of values are numeric
        var vals = rows.slice(0,30).map(function(r){return getVal(r,ci);}).filter(isNum);
        if (vals.length >= Math.max(1, Math.min(30, rows.length)*0.5)) numColIdxs.push(ci);
      }
    });

    return numColIdxs.slice(0,4).map(function(ci) {
      var col = cols[ci];
      var vals = rows.map(function(r){return getVal(r,ci);}).filter(isNum).map(toNum);
      if (!vals.length) return null;
      var total = vals.reduce(function(s,v){return s+v;},0);
      var avg = total/vals.length;
      var mn = Math.min.apply(null,vals), mx = Math.max.apply(null,vals);
      var spark = vals.slice(-12);
      var half = Math.floor(vals.length/2);
      var avg1 = half>0 ? vals.slice(0,half).reduce(function(s,v){return s+v;},0)/half : avg;
      var avg2 = (vals.length-half)>0 ? vals.slice(half).reduce(function(s,v){return s+v;},0)/(vals.length-half) : avg;
      var delta = avg1 !== 0 ? (avg2-avg1)/Math.abs(avg1) : 0;
      return { name: col.name, value: fmtNum(avg), total: fmtNum(total), min: fmtNum(mn), max: fmtNum(mx), count: vals.length, delta: delta, deltaStr: fmtPct(delta), spark: spark };
    }).filter(Boolean);
  }

  // ── Chart derivation (bar + line only) ───────────────────────────────────
  function deriveCharts(dataset) {
    var rows = dataset.rows, cols = dataset.columns, charts = [];

    // Classify columns
    var numIdxs = [], catIdxs = [], dateIdxs = [];
    cols.forEach(function(col, ci) {
      if (NUMERIC_TYPES[col.type]) {
        numIdxs.push(ci);
      } else if (DATE_TYPES[col.type]) {
        dateIdxs.push(ci);
      } else if (TEXT_TYPES[col.type]) {
        // Check cardinality for categorical use
        var uniq = new Set(rows.slice(0,50).map(function(r){return getVal(r,ci);}).filter(function(v){return v!==null&&v!==undefined&&v!=='';} )).size;
        if (uniq >= 2 && uniq <= 25) catIdxs.push(ci);
      }
    });

    // Fallback: if no classified cols, infer from values
    if (!numIdxs.length && !catIdxs.length) {
      cols.forEach(function(col, ci) {
        var vals30 = rows.slice(0,30).map(function(r){return getVal(r,ci);});
        var numCount = vals30.filter(isNum).length;
        if (numCount >= vals30.length*0.5) numIdxs.push(ci);
        else {
          var uniq = new Set(vals30.filter(Boolean)).size;
          if (uniq >= 2 && uniq <= 20) catIdxs.push(ci);
        }
      });
    }

    // 1. Avg metric by top categorical col
    if (catIdxs.length && numIdxs.length) {
      var ci=catIdxs[0], mi=numIdxs[0], g={};
      rows.forEach(function(r){ var k=String(getVal(r,ci)||'Unknown'); if(!g[k]) g[k]={sum:0,n:0}; var v=getVal(r,mi); if(isNum(v)){g[k].sum+=toNum(v);g[k].n++;} });
      var s=Object.keys(g).map(function(k){return{label:k,value:g[k].n?g[k].sum/g[k].n:0};}).sort(function(a,b){return b.value-a.value;}).slice(0,8);
      if (s.length>=2) charts.push({type:'bar',title:'Avg '+cols[mi].name+' by '+cols[ci].name,data:s,question:'Which '+cols[ci].name+' has the highest avg '+cols[mi].name+'?',_xLabel:cols[ci].name,_yLabel:'Avg '+cols[mi].name});
    }

    // 2. Count by category
    if (catIdxs.length) {
      var ci2=catIdxs.length>1?catIdxs[1]:catIdxs[0], freq={};
      rows.forEach(function(r){ var k=String(getVal(r,ci2)||'Unknown'); freq[k]=(freq[k]||0)+1; });
      var fs=Object.keys(freq).map(function(k){return{label:k,value:freq[k]};}).sort(function(a,b){return b.value-a.value;}).slice(0,8);
      if (fs.length>=2&&(catIdxs.length>1||charts.length===0)) charts.push({type:'bar',title:'Count by '+cols[ci2].name,data:fs,question:'How many records per '+cols[ci2].name+'?',_xLabel:cols[ci2].name,_yLabel:'Count'});
    }

    // 3. Time series line (date col + metric col)
    if (dateIdxs.length && numIdxs.length) {
      var di=dateIdxs[0], mi2=numIdxs[0], tg={};
      rows.forEach(function(r){ var d=new Date(String(getVal(r,di)||'')); if(isNaN(d)) return; var k=d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0'); if(!tg[k])tg[k]={sum:0,n:0}; var v=getVal(r,mi2); if(isNum(v)){tg[k].sum+=toNum(v);tg[k].n++;} });
      var ts=Object.keys(tg).sort().map(function(k){return{label:k,value:tg[k].n?tg[k].sum/tg[k].n:0};});
      if (ts.length>=2) charts.push({type:'line',title:cols[mi2].name+' trend over time',data:ts,question:'How has '+cols[mi2].name+' trended over time?',_xLabel:'Date',_yLabel:cols[mi2].name});
    }

    // 4. Distribution histogram of primary numeric col
    if (numIdxs.length) {
      var hci=numIdxs[0];
      var hv=rows.map(function(r){return getVal(r,hci);}).filter(isNum).map(toNum);
      if (hv.length>=5) {
        var mn=Math.min.apply(null,hv), mx=Math.max.apply(null,hv), binCnt=Math.min(8,Math.ceil(Math.sqrt(hv.length))), bw=(mx-mn)/binCnt||1;
        var bd=[]; for(var b=0;b<binCnt;b++){ var lo=mn+b*bw,hi=mn+(b+1)*bw; bd.push({label:fmtNum(lo)+'\u2013'+fmtNum(hi),value:hv.filter(function(v){return v>=lo&&(b===binCnt-1?v<=hi:v<hi);}).length}); }
        if (bd.length>1) charts.push({type:'bar',title:'Distribution: '+cols[hci].name,data:bd,question:'What is the distribution of '+cols[hci].name+'?',_xLabel:cols[hci].name,_yLabel:'Count'});
      }
    }

    // 5. Second numeric by first categorical
    if (numIdxs.length>1 && catIdxs.length) {
      var ci5=catIdxs[0], mi5=numIdxs[1], g5={};
      rows.forEach(function(r){ var k=String(getVal(r,ci5)||'Unknown'); if(!g5[k])g5[k]={sum:0,n:0}; var v=getVal(r,mi5); if(isNum(v)){g5[k].sum+=toNum(v);g5[k].n++;} });
      var s5=Object.keys(g5).map(function(k){return{label:k,value:g5[k].n?g5[k].sum/g5[k].n:0};}).sort(function(a,b){return b.value-a.value;}).slice(0,8);
      if (s5.length>=2) charts.push({type:'bar',title:'Avg '+cols[mi5].name+' by '+cols[ci5].name,data:s5,question:'How does '+cols[mi5].name+' compare across '+cols[ci5].name+'?',_xLabel:cols[ci5].name,_yLabel:'Avg '+cols[mi5].name});
    }

    return charts.slice(0,6);
  }

  // ── Sparkline SVG ─────────────────────────────────────────────────────────
  function sparkSVG(vals, color) {
    if (!vals||vals.length<2) return '';
    var w=80, h=28, mn=Math.min.apply(null,vals), mx=Math.max.apply(null,vals), rng=mx-mn||1;
    var pts=vals.map(function(v,i){ return ((i/(vals.length-1))*w).toFixed(1)+','+(h-((v-mn)/rng)*h).toFixed(1); }).join(' ');
    return '<svg width="'+w+'" height="'+h+'" viewBox="0 0 '+w+' '+h+'"><polyline points="'+pts+'" fill="none" stroke="'+color+'" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>';
  }

  // ── Chart.js rendering ────────────────────────────────────────────────────
  var chartInstances = [];
  function destroyCharts() { chartInstances.forEach(function(c){try{c.destroy();}catch(e){}}); chartInstances=[]; }

  function loadChartJs() {
    if (window.Chart) return Promise.resolve();
    return new Promise(function(resolve,reject){
      var s=document.createElement('script');
      s.src='https://cdn.jsdelivr.net/npm/chart.js@4.4.0/dist/chart.umd.min.js';
      s.onload=resolve; s.onerror=function(){resolve();};  // don't block on CDN failure
      document.head.appendChild(s);
    });
  }

  function renderChartCanvas(canvas, chart, isDark) {
    if (!window.Chart||!canvas) return;
    var tc=isDark?'#CDCCCA':'#28251D', gc=isDark?'#393836':'#D4D1CA', primary='#20808D';
    var labels=chart.data.map(function(d){return d.label;}), vals=chart.data.map(function(d){return d.value;});
    var isHoriz=chart.type==='bar'&&labels.some(function(l){return String(l).length>10;});
    var cfg={
      type:chart.type==='line'?'line':'bar',
      data:{ labels:labels, datasets:[{
        data:vals,
        backgroundColor:chart.type==='line'?'transparent':primary+'88',
        borderColor:primary, borderWidth:chart.type==='line'?2:0,
        borderRadius:chart.type==='bar'?4:0,
        pointBackgroundColor:primary, pointRadius:chart.type==='line'?3:0,
        tension:0.35,
        fill:chart.type==='line'?{target:'origin',above:primary+'18'}:false
      }]},
      options:{
        responsive:true, maintainAspectRatio:false,
        indexAxis:isHoriz?'y':'x',
        plugins:{ legend:{display:false}, tooltip:{callbacks:{label:function(ctx){return fmtNum(ctx.parsed[isHoriz?'x':'y']);}}} },
        scales:{
          x:{ grid:{color:gc,lineWidth:0.5}, ticks:{color:tc,font:{size:10},maxRotation:isHoriz?0:35,maxTicksLimit:8},
              title:{ display:!isHoriz, text:chart._xLabel||'', color:tc, font:{size:10}, padding:{top:4} } },
          y:{ grid:{color:gc,lineWidth:0.5}, ticks:{color:tc,font:{size:10},callback:function(v){return fmtNum(v);}},
              title:{ display:isHoriz||true, text:chart._yLabel||'', color:tc, font:{size:10}, padding:{bottom:4} } }
        }
      }
    };
    chartInstances.push(new window.Chart(canvas,cfg));
  }

  // ── Gate UI ───────────────────────────────────────────────────────────────
  function renderGate(report, el, onProceed) {
    el.innerHTML='';
    var wrap=document.createElement('div'); wrap.className='dash-gate';
    var hasBlocks=report.issues.length>0;
    wrap.innerHTML='<div class="dash-gate-title">'+(report.pass?'<span class="dash-gate-icon ok">&#10003;</span> Data Readiness Check Passed':'<span class="dash-gate-icon fail">&#9888;</span> Data Needs Attention Before Dashboarding')+'</div>'+
      '<div class="dash-gate-sub">'+(report.pass?'All quality checks passed. Building dashboard\u2026':'Presenting incomplete or duplicate data in a dashboard is bad practice. Fix the issues below first.')+'</div>';

    if (report.issues.length) {
      var il=document.createElement('div'); il.className='dash-gate-section';
      il.innerHTML='<div class="dash-gate-section-title">Blocking issues</div>';
      report.issues.forEach(function(i){ var r=document.createElement('div'); r.className='dash-gate-row block'; r.innerHTML='<span class="dash-dot red"></span><div><div class="dash-row-msg">'+escH(i.msg)+'</div>'+(i.detail?'<div class="dash-row-detail">'+escH(i.detail)+'</div>':'')+'</div>'; il.appendChild(r); });
      wrap.appendChild(il);
    }
    if (report.warnings.length) {
      var wl=document.createElement('div'); wl.className='dash-gate-section';
      wl.innerHTML='<div class="dash-gate-section-title">Quality notes</div>';
      report.warnings.forEach(function(w){ var r=document.createElement('div'); r.className='dash-gate-row warn'; r.innerHTML='<span class="dash-dot '+(w.severity==='info'?'blue':'amber')+'"></span><div><div class="dash-row-msg">'+escH(w.msg)+'</div>'+(w.detail?'<div class="dash-row-detail">'+escH(w.detail)+'</div>':'')+'</div>'; wl.appendChild(r); });
      wrap.appendChild(wl);
    }
    if (report.passed.length) {
      var pl=document.createElement('div'); pl.className='dash-gate-section';
      pl.innerHTML='<div class="dash-gate-section-title">Checks passed</div>';
      report.passed.forEach(function(p){ var r=document.createElement('div'); r.className='dash-gate-row'; r.innerHTML='<span class="dash-dot green"></span><div class="dash-row-msg">'+escH(p)+'</div>'; pl.appendChild(r); });
      wrap.appendChild(pl);
    }
    var ba=document.createElement('div'); ba.className='dash-gate-actions';
    if (!hasBlocks) {
      var btn=document.createElement('button'); btn.className='dash-btn-primary'; btn.textContent='Build Dashboard'; btn.addEventListener('click',onProceed); ba.appendChild(btn);
    } else {
      var hint=document.createElement('div'); hint.className='dash-gate-hint'; hint.textContent='Fix the blocking issues in the Grid or Column Editor, then return to the Dashboard tab.'; ba.appendChild(hint);
      var ob=document.createElement('button'); ob.className='dash-btn-secondary'; ob.textContent='Build anyway (quality caveats shown)'; ob.addEventListener('click',onProceed); ba.appendChild(ob);
    }
    wrap.appendChild(ba);
    el.appendChild(wrap);
  }

  // ── Dashboard render ──────────────────────────────────────────────────────
  function renderDashboard(dataset, report, el) {
    destroyCharts();
    el.innerHTML='';
    var isDark=document.documentElement.classList.contains('dark');
    var kpis=deriveKPIs(dataset), charts=deriveCharts(dataset);
    var dsName=(dataset.name||'Dataset').replace(/\.[^.]+$/,'');
    var now=new Date().toLocaleString();

    var dash=document.createElement('div'); dash.className='dash-root';

    // Header
    var hdr=document.createElement('div'); hdr.className='dash-header';
    hdr.innerHTML='<div class="dash-hdr-left"><div class="dash-title">'+escH(dsName)+'</div><div class="dash-meta">'+dataset.rows.length.toLocaleString()+' rows \u00b7 '+dataset.columns.length+' cols \u00b7 '+escH(now)+'</div></div>'+
      '<div class="dash-hdr-right">'+
      (report.warnings.length?'<span class="dash-quality-badge warn">&#9888; '+report.warnings.length+' note'+(report.warnings.length>1?'s':'')+'</span>':'<span class="dash-quality-badge ok">&#10003; Quality passed</span>')+
      '<button class="dash-export-btn" id="dash-csv-btn">&#8681; Export CSV</button></div>';
    dash.appendChild(hdr);

    // Findings Rail (PR AU)  -  above KPI row
    var frContainer = document.createElement('div');
    frContainer.id = 'findings-rail-container';
    if (typeof FindingsRail !== 'undefined') {
      window.__dg_currentDataset = dataset;
      window.__dg_lastFindings = Array.isArray(dataset && dataset.findings) ? dataset.findings : [];
      FindingsRail.render(dataset, frContainer);
    }
    dash.appendChild(frContainer);
    // Proof chain rail -- SQL lineage on each finding card
    if (typeof ProofChainRail !== 'undefined') {
      var pcrFinds = Array.isArray(window.__dg_lastFindings) ? window.__dg_lastFindings : [];
      setTimeout(function() { ProofChainRail.renderInline(frContainer, dataset, pcrFinds); }, 150);
    }

    // KPI row (3-4 max)
    if (kpis.length) {
      var kr=document.createElement('div'); kr.className='dash-kpi-row';
            // Register provenance for each KPI upfront
      var _whatIfFirstLoad = !sessionStorage.getItem('dg_whatif_seen');
      var _provIds = kpis.map(function(kpi) {
        if (!dataset) return null;
        var colIdx = dataset.columns.findIndex(function(c){ return c.name === kpi.name; });
        if (colIdx < 0) return null;
        return window.ProvenanceEngine ? ProvenanceEngine.registerKPI(dataset, colIdx, 'SUM') : null;
      });
      kpis.forEach(function(kpi,i){
        var card=document.createElement('div'); card.className='dash-kpi-card'+(i===0?' primary':'');
        card.dataset.kpiName = kpi.name;
        card.dataset.kpiOriginal = kpi.value;
        var ragC=kpi.delta>0.05?RAG.green:kpi.delta<-0.05?RAG.red:RAG.gray;
        var arrow=kpi.delta>0?'\u2191':kpi.delta<0?'\u2193':'\u2192';

        // What-if hint  -  shows once, first card only
        var hintHtml = (i===0 && _whatIfFirstLoad)
          ? '<div class="kpi-whatif-hint">Click any number to model a scenario</div>'
          : '';

        card.innerHTML=
          '<div class="dash-kpi-label">'+escH(kpi.name)+'</div>'+
          '<div class="dash-kpi-value-wrap">'+
            '<div class="dash-kpi-value" title="Click to enter a what-if scenario value" ' + (_provIds[i] ? 'data-prov-id="'+_provIds[i]+'"' : '') + '>'+escH(kpi.value)+'</div>'+
            '<input class="kpi-whatif-input hidden" type="number" step="any" placeholder="Enter scenario value" aria-label="What-if value for '+escH(kpi.name)+'" />'+
          '</div>'+
          hintHtml+
          '<div class="dash-kpi-footer"><span class="dash-delta" style="background:'+ragC.bg+';color:'+ragC.text+'">'+arrow+' '+escH(kpi.deltaStr||'\u2014')+'</span><span class="dash-spark">'+sparkSVG(kpi.spark,ragC.dot)+'</span></div>'+
          '<div class="dash-kpi-sub">min '+escH(kpi.min)+' \u00b7 max '+escH(kpi.max)+'</div>';

        // Click value to activate what-if input OR show provenance
        card.addEventListener('click', function(e) {
          if (e.target.classList.contains('kpi-whatif-input')) return;
          // Provenance: if clicked directly on the value element with a prov-id
          var valEl2 = card.querySelector('.dash-kpi-value');
          if (e.target === valEl2 && valEl2.dataset.provId && window.ProvenanceEngine) {
            ProvenanceEngine.show(valEl2.dataset.provId);
            return;
          }
          var valEl = card.querySelector('.dash-kpi-value');
          var inputEl = card.querySelector('.kpi-whatif-input');
          var hintEl = card.querySelector('.kpi-whatif-hint');
          if (!inputEl) return;
          // Dismiss hint permanently
          if (hintEl) { hintEl.style.display='none'; sessionStorage.setItem('dg_whatif_seen','1'); }
          valEl.classList.add('hidden');
          inputEl.classList.remove('hidden');
          inputEl.value = parseFloat(kpi.value.replace(/[^0-9.-]/g,'')) || '';
          inputEl.focus();
          inputEl.select();
        });

        // On input change: recompute delta vs original
        card.addEventListener('input', function(e) {
          if (!e.target.classList.contains('kpi-whatif-input')) return;
          var inputEl = e.target;
          var newVal = parseFloat(inputEl.value);
          if (isNaN(newVal)) return;
          var orig = parseFloat(kpi.value.replace(/[^0-9.-]/g,'')) || 0;
          var diff = newVal - orig;
          var pct = orig !== 0 ? ((diff / Math.abs(orig)) * 100).toFixed(1) : '0';
          var sign = diff >= 0 ? '+' : '';
          var deltaEl = card.querySelector('.dash-delta');
          if (deltaEl) {
            var newRag = diff > 0 ? RAG.green : diff < 0 ? RAG.red : RAG.gray;
            var newArrow = diff > 0 ? '\u2191' : diff < 0 ? '\u2193' : '\u2192';
            deltaEl.style.background = newRag.bg;
            deltaEl.style.color = newRag.text;
            deltaEl.textContent = newArrow + ' ' + sign + pct + '% vs actual';
          }
          // Scenario badge
          var sub = card.querySelector('.dash-kpi-sub');
          if (sub) sub.innerHTML = '\u26A0 Scenario mode \u00b7 actual: '+escH(kpi.value);
        });

        // Escape / blur: restore original
        card.addEventListener('keydown', function(e) {
          if (e.key !== 'Escape') return;
          var inputEl = card.querySelector('.kpi-whatif-input');
          var valEl = card.querySelector('.dash-kpi-value');
          if (!inputEl) return;
          inputEl.classList.add('hidden');
          valEl.classList.remove('hidden');
          var deltaEl = card.querySelector('.dash-delta');
          if (deltaEl) { deltaEl.style.background=ragC.bg; deltaEl.style.color=ragC.text; deltaEl.textContent=arrow+' '+escH(kpi.deltaStr||'\u2014'); }
          var sub = card.querySelector('.dash-kpi-sub');
          if (sub) sub.innerHTML='min '+escH(kpi.min)+' \u00b7 max '+escH(kpi.max);
        });

        card.addEventListener('focusout', function(e) {
          if (e.relatedTarget && card.contains(e.relatedTarget)) return;
          var inputEl = card.querySelector('.kpi-whatif-input');
          var valEl = card.querySelector('.dash-kpi-value');
          if (inputEl && !inputEl.classList.contains('hidden')) {
            inputEl.classList.add('hidden');
            valEl.classList.remove('hidden');
          }
        });

        kr.appendChild(card);
      });
      if (_whatIfFirstLoad) sessionStorage.setItem('dg_whatif_seen','1');
      dash.appendChild(kr);
    } else {
      var noKpi=document.createElement('div'); noKpi.className='dash-no-numeric';
      noKpi.textContent='No numeric columns detected. Add numeric data for KPI cards.';
      dash.appendChild(noKpi);
    }

    // Outlier banner (never silent)
    if (report.outlierCols&&report.outlierCols.length) {
      var ob=document.createElement('div'); ob.className='dash-outlier-banner';
      ob.innerHTML='<strong>Outliers visible:</strong> '+report.outlierCols.map(function(c){return escH(c.name)+' ('+c.count+' point'+(c.count>1?'s':'')+')'}).join(', ')+'. Shown in context per Tableau best practice \u2014 not removed.';
      dash.appendChild(ob);
    }

    // Chart grid (max 6)
    if (charts.length) {
      var cg=document.createElement('div'); cg.className='dash-chart-grid';
      charts.forEach(function(chart){
        var card=document.createElement('div'); card.className='dash-chart-card';
        var q=document.createElement('div'); q.className='dash-chart-title'; q.textContent=chart.question;
        var topD=chart.data[0];
        var insightTxt = topD ? 'Top: ' + String(topD.label).substring(0,22) + ' · ' + fmtNum(topD.value) : chart.title;
        var ins=document.createElement('div'); ins.className='dash-chart-insight'; ins.innerHTML=insightTxt;
        var cw=document.createElement('div'); cw.className='dash-chart-wrap';
        var canvas=document.createElement('canvas');
        cw.appendChild(canvas); card.appendChild(q); card.appendChild(ins); card.appendChild(cw); cg.appendChild(card);
        loadChartJs().then(function(){ renderChartCanvas(canvas,chart,isDark); });
      });
      dash.appendChild(cg);
    } else {
      var noChart=document.createElement('div'); noChart.className='dash-no-numeric';
      noChart.textContent='Not enough structured data to auto-generate charts. Try adding numeric or categorical columns.';
      dash.appendChild(noChart);
    }

    // Footer quality notes
    if (report.warnings.length) {
      var ft=document.createElement('div'); ft.className='dash-footer';
      ft.innerHTML='<strong>Quality notes:</strong> '+report.warnings.map(function(w){return escH(w.msg);}).join(' \u00b7 ');
      dash.appendChild(ft);
    }

    el.appendChild(dash);

    // Export CSV
    var csvBtn=el.querySelector('#dash-csv-btn');
    if (csvBtn) {
      csvBtn.addEventListener('click', function(){
        var colNames=dataset.columns.map(function(c){return c.name;});
        var lines=[colNames.map(function(c){return JSON.stringify(c);}).join(',')];
        dataset.rows.forEach(function(r){ lines.push(dataset.columns.map(function(col,ci){var v=getVal(r,ci);return v===null||v===undefined?'':JSON.stringify(String(v));}).join(',')); });
        var blob=new Blob([lines.join('\n')],{type:'text/csv'});
        var a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download=dsName+'_dashboard.csv'; a.click();
        setTimeout(function(){URL.revokeObjectURL(a.href);},2000);
      });
    }
  }

  // ── Public render ─────────────────────────────────────────────────────────
  function render(dataset, el) {
    el.innerHTML='';
    if (!dataset) {
      el.innerHTML='<div class="dash-empty"><div class="dash-empty-icon">&#9783;</div><div class="dash-empty-title">No data loaded</div><div class="dash-empty-sub">Drop a CSV file anywhere to get started.</div></div>';
      return;
    }
    var report=runReadinessCheck(dataset);
    renderGate(report, el, function(){ renderDashboard(dataset, report, el); });
    if (report.pass) {
      setTimeout(function(){ renderDashboard(dataset, report, el); }, 350);
    }
  }

  return { render: render, runReadinessCheck: runReadinessCheck };
})();

