      if (type === '837') return parse837(env.segments);
      var cols = [
        { name: 'segment_id', type: 'STR' },
        { name: 'elements',   type: 'STR' },
        { name: 'raw',        type: 'STR' }
      ];
      var gRows = env.segments.map(function (s) {
        return [s[0] || '', s.slice(1).join('|'), s.join(env.elemSep)];
      });
      return { columns: cols, rows: gRows, transactionType: type };
