  const rows = extractRows(payload);
  if (rows.length === 0) {
    return errorSource(id, kind, `${kind} payload had no usable array of row objects`, base);
  }

  const possibleKeys = inferJoinKeys(rows);
  const trust = assignDefaultTrust(base);
