      out.push({
        id,
        rows: sheet.rows,
        possibleKeys,
        trust: assignDefaultTrust({ kind: 'excel' }),
        meta: {
          ok: true,
          kind: 'excel',
          fileName: file,
          sheetName,
          rowCount: sheet.rows.length,
          needsManualKeySelection: possibleKeys.length === 0,
        },
      });
