  'were', 'what', 'which', 'how', 'many', 'much', 'with', 'without',
  'that', 'this', 'these', 'those', 'from', 'where', 'group', 'over',
  'time', 'top', 'bottom', 'highest', 'lowest', 'best', 'worst', 'count',
  'number', 'total', 'average', 'mean', 'avg', 'sum', 'display', 'give',
