    status: tone,
    tone,
    dotColor: STATE_DOT[tone],
    scoreText,
    label: STATUS_LABEL[tone] || STATUS_LABEL.idle,
    summary: g && typeof g.summary === 'string' ? g.summary : 'No dataset signals available.',
