    condition: (t) => q(t) + '.deceased = 1 AND LOWER(CAST(' + q(t) + '.discharge_disposition AS VARCHAR)) NOT IN (\'20\',\'expired\',\'dead\',\'deceased\',\'40\',\'41\',\'42\')',
